  Object.assign(ICONS, UNICONS);

  const NOTE_IMPORT_ACCEPT = 'image/*,.csv,text/csv';
  const IMPORT_IMAGE_MIN_WIDTH = 96;
  const IMPORT_IMAGE_MAX_WIDTH = 960;
  const IMPORT_IMAGE_FULL_WIDTH = 'full';

  function getImportMaxWidth(pane = null) {
    const paneWidth = pane && pane.ui && pane.ui.liveEditor
      ? Math.max(IMPORT_IMAGE_MIN_WIDTH, Math.floor((pane.ui.liveEditor.clientWidth || IMPORT_IMAGE_MAX_WIDTH) - 24))
      : IMPORT_IMAGE_MAX_WIDTH;
    return Math.max(IMPORT_IMAGE_MIN_WIDTH, Math.min(IMPORT_IMAGE_MAX_WIDTH, paneWidth));
  }

  function isFullImportWidthValue(value) {
    return String(value || '').trim().toLowerCase() === IMPORT_IMAGE_FULL_WIDTH;
  }

  function clampImportWidth(value, pane = null) {
    const numeric = Number(value);
    const maxWidth = getImportMaxWidth(pane);
    if (!Number.isFinite(numeric)) return Math.min(480, maxWidth);
    return Math.max(IMPORT_IMAGE_MIN_WIDTH, Math.min(maxWidth, Math.round(numeric)));
  }

  function normalizeStoredImportWidth(value, pane = null) {
    if (isFullImportWidthValue(value)) return IMPORT_IMAGE_FULL_WIDTH;
    return clampImportWidth(value, pane);
  }

  function getImportWidthStyleValue(value, pane = null) {
    if (isFullImportWidthValue(value)) return '100%';
    return `${clampImportWidth(value, pane)}px`;
  }

  function escapeRegExpText(value) {
    return String(value || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  function createImportedImageId() {
    return `img_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 9)}`;
  }

  function isImportableImageFile(file) {
    if (!file) return false;
    if (file.kind === 'image' && typeof file.dataUrl === 'string') return true;
    const type = String(file.type || '').toLowerCase();
    const name = String(file.name || '').toLowerCase();
    return type.startsWith('image/') || /\.(png|jpe?g|gif|webp|bmp|svg)$/i.test(name);
  }

  function isImportableCsvFile(file) {
    if (!file) return false;
    if (file.kind === 'csv' && typeof file.text === 'string') return true;
    const type = String(file.type || '').toLowerCase();
    const name = String(file.name || '').toLowerCase();
    return type.includes('csv') || /\.csv$/i.test(name);
  }

  function hasImportableFiles(fileList) {
    return Array.from(fileList || []).some((file) => isImportableImageFile(file) || isImportableCsvFile(file));
  }

  function dataTransferHasImportableFiles(dataTransfer) {
    if (!dataTransfer) return false;
    if (hasImportableFiles(dataTransfer.files)) return true;
    return Array.from(dataTransfer.types || []).includes('Files');
  }

  function pickNoteImportFiles() {
    if (window.api && typeof window.api.openImportFiles === 'function') {
      return window.api.openImportFiles()
        .then((result) => {
          if (!result || result.canceled) return [];
          return Array.isArray(result.items) ? result.items : [];
        })
        .catch(() => []);
    }
    return Promise.resolve([]);
  }

  function readFileAsDataUrl(file) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onerror = () => reject(reader.error || new Error('Failed to read file.'));
      reader.onload = () => resolve(String(reader.result || ''));
      reader.readAsDataURL(file);
    });
  }

  function readFileAsText(file) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onerror = () => reject(reader.error || new Error('Failed to read file.'));
      reader.onload = () => resolve(String(reader.result || ''));
      reader.readAsText(file);
    });
  }

  function measureImportedImage(dataUrl) {
    return new Promise((resolve) => {
      const img = new Image();
      img.onload = () => {
        resolve({
          width: Number.isFinite(img.naturalWidth) ? img.naturalWidth : 0,
          height: Number.isFinite(img.naturalHeight) ? img.naturalHeight : 0
        });
      };
      img.onerror = () => resolve({ width: 0, height: 0 });
      img.src = dataUrl;
    });
  }

  function detectCsvDelimiter(text) {
    const source = String(text || '');
    const lines = source.split(/\r?\n/).filter((line) => line.trim()).slice(0, 8);
    if (!lines.length) return ',';
    const candidates = [',', ';', '\t'];
    let bestDelimiter = ',';
    let bestScore = -1;
    const countDelimiter = (line, delimiter) => {
      let count = 0;
      let inQuotes = false;
      for (let index = 0; index < line.length; index += 1) {
        const char = line[index];
        if (char === '"') {
          if (inQuotes && line[index + 1] === '"') {
            index += 1;
          } else {
            inQuotes = !inQuotes;
          }
          continue;
        }
        if (!inQuotes && char === delimiter) count += 1;
      }
      return count;
    };
    candidates.forEach((delimiter) => {
      const counts = lines.map((line) => countDelimiter(line, delimiter));
      const nonZero = counts.filter((count) => count > 0);
      if (!nonZero.length) return;
      const score = nonZero.reduce((sum, count) => sum + count, 0) - Math.abs(Math.max(...counts) - Math.min(...counts)) * 0.5;
      if (score > bestScore) {
        bestScore = score;
        bestDelimiter = delimiter;
      }
    });
    return bestDelimiter;
  }

  function parseCsvText(text, delimiter = detectCsvDelimiter(text)) {
    const src = String(text || '');
    const rows = [];
    let row = [];
    let cell = '';
    let inQuotes = false;
    for (let index = 0; index < src.length; index += 1) {
      const char = src[index];
      const next = src[index + 1];
      if (char === '"') {
        if (inQuotes && next === '"') {
          cell += '"';
          index += 1;
        } else {
          inQuotes = !inQuotes;
        }
        continue;
      }
      if (!inQuotes && char === delimiter) {
        row.push(cell);
        cell = '';
        continue;
      }
      if (!inQuotes && (char === '\n' || char === '\r')) {
        if (char === '\r' && next === '\n') index += 1;
        row.push(cell);
        rows.push(row);
        row = [];
        cell = '';
        continue;
      }
      cell += char;
    }
    if (cell.length || row.length) {
      row.push(cell);
      rows.push(row);
    }
    return rows
      .map((cells) => cells.map((value) => String(value || '')))
      .filter((cells) => cells.some((value) => value.trim() !== ''));
  }

  function escapeMarkdownTableCell(value) {
    return String(value || '')
      .replace(/\r?\n/g, '<br>')
      .replace(/\|/g, '\\|')
      .trim();
  }

  function convertCsvTextToMarkdownTable(text) {
    const rows = parseCsvText(text);
    if (!rows.length) return '';
    const columnCount = rows.reduce((max, row) => Math.max(max, row.length), 0);
    const paddedRows = rows.map((row) => {
      const nextRow = row.slice(0, columnCount);
      while (nextRow.length < columnCount) nextRow.push('');
      return nextRow;
    });
    const header = paddedRows[0].map(escapeMarkdownTableCell);
    const divider = paddedRows[0].map(() => '---');
    const body = paddedRows.slice(1).map((row) => row.map(escapeMarkdownTableCell));
    return [
      `| ${header.join(' | ')} |`,
      `| ${divider.join(' | ')} |`,
      ...body.map((row) => `| ${row.join(' | ')} |`)
    ].join('\n');
  }

  function buildImportedImageSnippet({ dataUrl, name, width }) {
    const imageId = createImportedImageId();
    const alt = escapeHtmlText(String(name || 'Image').replace(/\.[^.]+$/, '') || 'Image');
    const safeWidth = clampImportWidth(width);
    return {
      imageId,
      snippet: `<div class="noto-imported-image" data-noto-image-id="${imageId}" data-noto-image-width="${safeWidth}" style="width: ${safeWidth}px;"><img src="${dataUrl}" alt="${alt}" data-noto-image-id="${imageId}" draggable="false" /></div>\n`
    };
  }

  async function buildNoteImportSnippets(files, pane = null) {
    const snippets = [];
    for (const file of Array.from(files || [])) {
      if (isImportableImageFile(file)) {
        const dataUrl = typeof file.dataUrl === 'string' && file.dataUrl
          ? file.dataUrl
          : await readFileAsDataUrl(file);
        if (!dataUrl) continue;
        const measured = await measureImportedImage(dataUrl);
        const preferredWidth = clampImportWidth(measured.width || 480, pane);
        snippets.push({
          kind: 'image',
          ...buildImportedImageSnippet({
            dataUrl,
            name: file.name || 'Image',
            width: preferredWidth
          })
        });
        continue;
      }
      if (isImportableCsvFile(file)) {
        const text = typeof file.text === 'string'
          ? file.text
          : await readFileAsText(file);
        const table = convertCsvTextToMarkdownTable(text);
        if (!table) continue;
        snippets.push({
          kind: 'csv',
          snippet: table
        });
      }
    }
    return snippets;
  }

  function getActivePaneSelection(pane, fallbackPos = null) {
    const activeTab = pane && typeof pane.getActiveTab === 'function' ? pane.getActiveTab() : null;
    const lastSelection = pane && pane.live && pane.live.lastSelection && Number.isFinite(pane.live.lastSelection.from)
      ? pane.live.lastSelection
      : null;
    const selection = pane && pane.live && pane.live.cmApi && typeof pane.live.cmApi.getSelection === 'function'
      ? pane.live.cmApi.getSelection()
      : null;
    if (selection && Number.isFinite(selection.from) && Number.isFinite(selection.to)) {
      return selection;
    }
    if (lastSelection) return lastSelection;
    const pos = Number.isFinite(fallbackPos)
      ? fallbackPos
      : (activeTab && Number.isFinite(activeTab.cursorOffset) ? activeTab.cursorOffset : 0);
    return { from: pos, to: pos, anchor: pos, head: pos, empty: true };
  }

  function dispatchPaneEditorChange(pane, change, selection = null, options = {}) {
    if (!pane) return false;
    const tab = typeof pane.getActiveTab === 'function' ? pane.getActiveTab() : null;
    if (!tab || isPopupTab(tab) || isStorageTab(tab)) return false;
    if (tab.isReadOnly) {
      showToast('Viewer access: editing disabled.', 'info', 1600);
      return false;
    }
    const editorView = pane.live && pane.live.cmView;
    const focus = options.focus !== false;
    if (editorView && typeof editorView.dispatch === 'function') {
      editorView.dispatch({
        changes: change,
        ...(selection ? { selection } : {}),
        ...(options.scrollIntoView === false ? {} : { scrollIntoView: true })
      });
      if (focus && pane.live && pane.live.cmApi && typeof pane.live.cmApi.focus === 'function') {
        pane.live.cmApi.focus();
      }
      return true;
    }
    const currentText = typeof tab.content === 'string' ? tab.content : '';
    const from = Math.max(0, Math.min(currentText.length, Number(change && change.from)));
    const to = Math.max(from, Math.min(currentText.length, Number(change && change.to)));
    const insert = String(change && Object.prototype.hasOwnProperty.call(change, 'insert') ? change.insert : '');
    const nextText = `${currentText.slice(0, from)}${insert}${currentText.slice(to)}`;
    const nextCaret = selection && Number.isFinite(selection.head) ? selection.head : (from + insert.length);
    pane.commitLiveEditorText(nextText, nextCaret, {
      preserveScroll: options.preserveScroll !== false,
      focus,
      anchorCaret: Boolean(options.anchorCaret)
    });
    return true;
  }

  function insertTextIntoPane(pane, text, options = {}) {
    if (!pane) return false;
    const selection = getActivePaneSelection(pane, options.insertPos);
    const insertText = String(text || '');
    const nextOffset = selection.from + insertText.length;
    return dispatchPaneEditorChange(
      pane,
      { from: selection.from, to: selection.to, insert: insertText },
      { anchor: nextOffset, head: nextOffset },
      { focus: options.focus !== false, preserveScroll: true, anchorCaret: true }
    );
  }

  function getDropInsertPos(pane, event) {
    if (!pane || !pane.live || !pane.live.cmView || typeof pane.live.cmView.posAtCoords !== 'function') return null;
    const pos = pane.live.cmView.posAtCoords({ x: event.clientX, y: event.clientY });
    return Number.isFinite(pos) ? pos : null;
  }

  async function insertImportedFilesIntoPane(pane, files, options = {}) {
    if (!pane) return false;
    const snippets = await buildNoteImportSnippets(files, pane);
    if (!snippets.length) {
      showToast('No supported import files selected.', 'info');
      return false;
    }
    const selection = options.selection && Number.isFinite(options.selection.from)
      ? options.selection
      : getActivePaneSelection(pane, options.insertPos);
    const currentText = pane.getCurrentEditorText();
    const beforeChar = selection.from > 0 ? currentText.slice(selection.from - 1, selection.from) : '';
    const afterChar = selection.to < currentText.length ? currentText.slice(selection.to, selection.to + 1) : '';
    const joined = snippets.map((entry) => entry.snippet).join('\n\n');
    const insertText =
      `${selection.from > 0 && beforeChar !== '\n' ? '\n\n' : ''}` +
      joined +
      `${selection.to < currentText.length && afterChar !== '\n' ? '\n\n' : ''}`;
    const nextOffset = selection.from + insertText.length;
    const inserted = dispatchPaneEditorChange(
      pane,
      { from: selection.from, to: selection.to, insert: insertText },
      { anchor: nextOffset, head: nextOffset },
      { focus: true, preserveScroll: true, anchorCaret: true }
    );
    if (!inserted) return false;
    const imageCount = snippets.filter((entry) => entry.kind === 'image').length;
    const csvCount = snippets.filter((entry) => entry.kind === 'csv').length;
    if (imageCount && csvCount) showToast(`Imported ${imageCount} image${imageCount === 1 ? '' : 's'} and ${csvCount} CSV table${csvCount === 1 ? '' : 's'}.`, 'success');
    else if (imageCount) showToast(`Imported ${imageCount} image${imageCount === 1 ? '' : 's'}.`, 'success');
    else showToast(`Imported ${csvCount} CSV table${csvCount === 1 ? '' : 's'}.`, 'success');
    return true;
  }

  async function openImportPickerForPane(pane, preservedSelection = null) {
    const selection = preservedSelection && Number.isFinite(preservedSelection.from)
      ? preservedSelection
      : getActivePaneSelection(pane);
    const files = await pickNoteImportFiles();
    if (!files.length) return false;
    return insertImportedFilesIntoPane(pane, files, { selection });
  }

  function getNotePdfExportTitle(tab) {
    if (tab && typeof tab.title === 'string' && tab.title.trim()) return tab.title.trim();
    if (tab && typeof tab.path === 'string' && tab.path.trim()) {
      return getNoteDisplayName(tab.path.split('/').pop() || tab.path);
    }
    return 'Untitled note';
  }

  function getPdfExportThemeMode() {
    const rawTheme = String(document.documentElement.getAttribute('data-theme') || '').trim().toLowerCase();
    return rawTheme === 'dark' ? 'dark' : 'light';
  }

  function buildNotePdfExportMarkup(content) {
    const host = document.createElement('div');
    host.className = 'live-markdown-editor live-rich-editor cm-host md-view noto-pdf-export-root';
    renderMarkdownToPresentationElement(String(content || ''), host);
    host.querySelectorAll('input.task-list-item-checkbox[type="checkbox"]').forEach(box => {
      const span = document.createElement('span');
      span.className = 'task-list-item-checkbox' + (box.checked ? ' checked' : '');
      span.textContent = box.checked ? '☑' : '☐';
      if (box.parentNode) box.parentNode.replaceChild(span, box);
    });
    host.querySelectorAll('a[href]').forEach((link) => {
      link.setAttribute('rel', 'noreferrer noopener');
      link.setAttribute('target', '_blank');
    });
    return host.outerHTML;
  }

  async function exportPaneNoteAsPdf(pane, tab = null) {
    const targetPane = pane || activePane || null;
    const targetTab = tab || (targetPane && typeof targetPane.getActiveTab === 'function' ? targetPane.getActiveTab() : null);
    if (!targetPane || !targetTab || isStorageTab(targetTab) || isPopupTab(targetTab)) {
      showToast('Open a note to export it as PDF.', 'info');
      return false;
    }
    if (
      !window.api
      || typeof window.api.chooseNotePdfExportPath !== 'function'
      || typeof window.api.exportNotePdf !== 'function'
    ) {
      showToast('PDF export is not available in this build.', 'warning');
      return false;
    }
    const title = getNotePdfExportTitle(targetTab);
    let exportPathResult = null;
    try {
      exportPathResult = await window.api.chooseNotePdfExportPath({
        title,
        suggestedName: title,
        relativePath: targetTab.path || ''
      });
    } catch (error) {
      exportPathResult = {
        canceled: true,
        error: error && error.message ? String(error.message) : 'Failed to choose a PDF export path.'
      };
    }
    if (!exportPathResult || exportPathResult.canceled) {
      if (exportPathResult && exportPathResult.error) showToast(exportPathResult.error, 'warning');
      return false;
    }
    const currentContent = typeof targetPane.getCurrentEditorText === 'function'
      ? targetPane.getCurrentEditorText()
      : (typeof targetTab.content === 'string' ? targetTab.content : '');
    const exportResult = await runWithTaskLoadingOverlay(() => window.api.exportNotePdf({
      filePath: exportPathResult.filePath,
      title,
      html: buildNotePdfExportMarkup(currentContent),
      theme: getPdfExportThemeMode()
    }));
    if (!exportResult || !exportResult.success) {
      showToast(
        exportResult && exportResult.error
          ? exportResult.error
          : 'Failed to export this note as PDF.',
        'warning'
      );
      return false;
    }
    showToast(`Exported "${title}" as PDF.`, 'success');
    return true;
  }

  function findImportedImageOpeningTagRange(content, imageId) {
    const source = String(content || '');
    const safeId = escapeRegExpText(imageId);
    const pattern = new RegExp(`<div\\b[^>]*\\bdata-noto-image-id=(["'])${safeId}\\1[^>]*>`, 'i');
    const match = pattern.exec(source);
    if (!match) return null;
    return {
      from: match.index,
      to: match.index + match[0].length,
      tag: match[0]
    };
  }

  function getImportedImageBlockRanges(content) {
    const source = String(content || '');
    const pattern = /<div\b[^>]*\bclass=(["'])[^"']*\bnoto-imported-image\b[^"']*\1[^>]*\bdata-noto-image-id=(["'])([^"']+)\2[^>]*>[\s\S]*?<\/div>/gi;
    const ranges = [];
    let match;
    while ((match = pattern.exec(source))) {
      ranges.push({
        id: String(match[3] || ''),
        from: match.index,
        to: match.index + match[0].length
      });
    }
    return ranges;
  }

  function expandImportedImageBlockDeletionRange(content, range) {
    if (!range || !Number.isFinite(range.from) || !Number.isFinite(range.to)) return null;
    const source = String(content || '');
    let from = Math.max(0, range.from);
    let to = Math.max(from, range.to);
    if (source.slice(to, to + 1) === '\n') {
      to += 1;
    } else if (from > 0 && source.slice(from - 1, from) === '\n') {
      from -= 1;
    }
    return { from, to };
  }

  function findImportedImageBlockRangeById(content, imageId) {
    if (!imageId) return null;
    const ranges = getImportedImageBlockRanges(content);
    return ranges.find((range) => range.id === imageId) || null;
  }

  function findImportedImageBlockRangeBeforePosition(content, pos) {
    const source = String(content || '');
    const safePos = Math.max(0, Math.min(source.length, Number.isFinite(pos) ? pos : 0));
    const ranges = getImportedImageBlockRanges(source);
    for (let index = ranges.length - 1; index >= 0; index -= 1) {
      const expanded = expandImportedImageBlockDeletionRange(source, ranges[index]);
      if (!expanded) continue;
      if (expanded.to === safePos) return expanded;
    }
    return null;
  }

  function replaceOrAppendTagAttr(tag, attrName, attrValue) {
    const attrPattern = new RegExp(`\\b${escapeRegExpText(attrName)}=(["'])([\\s\\S]*?)\\1`, 'i');
    const serialized = `${attrName}="${String(attrValue || '')}"`;
    if (attrPattern.test(tag)) return tag.replace(attrPattern, serialized);
    return tag.replace(/>$/, ` ${serialized}>`);
  }

  function replaceOrAppendWidthStyle(tag, widthPx, pane = null) {
    const stylePattern = /\bstyle=(["'])([\s\S]*?)\1/i;
    const nextWidth = `width: ${getImportWidthStyleValue(widthPx, pane)};`;
    if (stylePattern.test(tag)) {
      return tag.replace(stylePattern, (_match, quote, styleValue) => {
        const declarations = String(styleValue || '')
          .split(';')
          .map((part) => part.trim())
          .filter((part) => part && !/^width\s*:/i.test(part));
        return `style=${quote}${[nextWidth.replace(/;$/, ''), ...declarations].join('; ')};${quote}`;
      });
    }
    return tag.replace(/>$/, ` style="${nextWidth}">`);
  }

