  const sidebarIconUniqueChoices = [];
  const sidebarSeenIds = new Set();
  const sidebarSeenSvg = new Set();
  SIDEBAR_ICON_CHOICES.forEach((item) => {
    if (!item || typeof item !== 'object') return;
    const id = typeof item.id === 'string' ? item.id.trim() : '';
    const label = typeof item.label === 'string' ? item.label.trim() : '';
    const svg = typeof item.svg === 'string' ? item.svg.trim() : '';
    if (!id || !label || !svg) return;
    if (sidebarSeenIds.has(id)) return;
    const svgKey = svg.replace(/\s+/g, ' ').trim();
    if (!svgKey || sidebarSeenSvg.has(svgKey)) return;
    sidebarSeenIds.add(id);
    sidebarSeenSvg.add(svgKey);
    const keywordSet = new Set(Array.isArray(item.keywords) ? item.keywords.map((kw) => String(kw || '').trim()).filter(Boolean) : []);
    sidebarIconUniqueChoices.push({
      id,
      label,
      svg,
      keywords: Array.from(keywordSet)
    });
  });
  SIDEBAR_ICON_CHOICES.length = 0;
  SIDEBAR_ICON_CHOICES.push(...sidebarIconUniqueChoices);

