  function normalizeMathAutocompleteCommand(command) {
    if (!command || typeof command !== 'object') return null;
    const code = String(command.code || '').trim();
    if (!code || !COMMON_MATH_COMMAND_CODES.has(code) || MATH_AUTOCOMPLETE_EXCLUDED_CODES.has(code)) {
      return null;
    }
    const insertOverride = MATH_AUTOCOMPLETE_INSERT_OVERRIDES.get(code);
    return {
      ...command,
      code,
      insert: typeof insertOverride === 'string' && insertOverride
        ? insertOverride
        : (typeof command.insert === 'string' ? command.insert : code)
    };
  }

  const mathAutocompleteCommands = allMathAutocompleteCommands
    .map(normalizeMathAutocompleteCommand)
    .filter(Boolean);
  let slashMenu = {
    el: document.getElementById('slash-menu'),
    isOpen: false,
    activeIndex: 0,
    filtered: [],
    targetPane: null,
    startPos: 0,
    replaceFrom: 0,
    isInserting: false,
    mode: 'slash',
    searchTerm: ''
  };
  const editorScrollAnimations = new WeakMap();
  const mathPreviewCache = new Map();
  const RENDERER_INLINE_DOLLAR_MATH_PATTERN = /(?<!\\)\$(?:[^$\n\\]|\\.)*?(?<!\\)\$/g;
  const RENDERER_BLOCK_DOLLAR_MATH_PATTERN = /\$\$[\s\S]*?\$\$/g;
  const RENDERER_BRACKET_MATH_PATTERN = /\\\[[\s\S]*?\\\]/g;
  const RENDERER_PAREN_MATH_PATTERN = /\\\([\s\S]*?\\\)/g;

  function getEditorLineHeight(editor) {
    const cmView = editor && editor.__cmView ? editor.__cmView : null;
    if (cmView && cmView.dom) {
      const cmStyle = window.getComputedStyle(cmView.dom);
      const cmParsed = Number.parseFloat(cmStyle.lineHeight);
      if (Number.isFinite(cmParsed)) return cmParsed;
    }
    const style = window.getComputedStyle(editor);
    const parsed = Number.parseFloat(style.lineHeight);
    if (Number.isFinite(parsed)) return parsed;
    const fontSize = Number.parseFloat(style.fontSize);
    return Number.isFinite(fontSize) ? fontSize * 1.4 : 20;
  }

  function normalizeEditorText(text) {
    return String(text || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  }

  function hasCodeMirrorEditor(editor) {
    return Boolean(editor && editor.__cmView && editor.__cmView.state);
  }

  function getCodeMirrorView(editor) {
    return hasCodeMirrorEditor(editor) ? editor.__cmView : null;
  }

  function getEditorSelectionStart(editor) {
    if (!editor) return 0;
    const cmView = getCodeMirrorView(editor);
    if (cmView) return cmView.state.selection.main.from;
    return Number.isFinite(editor.selectionStart) ? editor.selectionStart : 0;
  }

  function getCaretCoordinates(element, position) {
    const cmView = getCodeMirrorView(element);
    if (!cmView) return { top: 0, left: 0 };
    const len = cmView.state.doc.length;
    const safePos = Math.max(0, Math.min(len, Number.isFinite(position) ? position : 0));
    const rect = cmView.coordsAtPos(safePos);
    const rootRect = element.getBoundingClientRect();
    const scroller = cmView.scrollDOM || element;
    if (rect) {
      return {
        top: (rect.top - rootRect.top) + (scroller.scrollTop || 0),
        left: (rect.left - rootRect.left) + (scroller.scrollLeft || 0)
      };
    }
    return { top: 0, left: 0 };
  }

  function animateEditorScrollTo(editor, targetTop, duration = 220) {
    if (!editor) return;
    const clampedTarget = Math.max(0, Math.min(Math.max(0, editor.scrollHeight - editor.clientHeight), targetTop));
    const existing = editorScrollAnimations.get(editor);
    if (existing && existing.rafId) cancelAnimationFrame(existing.rafId);

    const startTop = editor.scrollTop;
    if (Math.abs(clampedTarget - startTop) < 0.5) {
      editor.scrollTop = clampedTarget;
      return;
    }

    const startTime = performance.now();
    const easeOutCubic = (t) => 1 - Math.pow(1 - t, 3);

    const step = (now) => {
      const elapsed = now - startTime;
      const progress = Math.min(1, elapsed / duration);
      const eased = easeOutCubic(progress);
      editor.scrollTop = startTop + ((clampedTarget - startTop) * eased);

      if (progress < 1) {
        const nextState = editorScrollAnimations.get(editor) || {};
        nextState.rafId = requestAnimationFrame(step);
        editorScrollAnimations.set(editor, nextState);
      } else {
        editor.scrollTop = clampedTarget;
        editorScrollAnimations.delete(editor);
      }
    };

    editorScrollAnimations.set(editor, { rafId: requestAnimationFrame(step) });
  }

  function cancelEditorScrollAnimation(editor) {
    if (!editor) return;
    const existing = editorScrollAnimations.get(editor);
    if (existing && existing.rafId) cancelAnimationFrame(existing.rafId);
    editorScrollAnimations.delete(editor);
  }

  function isFormattedTableEditingActive(editor) {
    if (!editor || !(editor instanceof Element)) return false;
    const activeInput = document.activeElement instanceof Element
      ? document.activeElement.closest('.noto-table-cell-input')
      : null;
    return Boolean(activeInput && editor.contains(activeInput));
  }

  function keepLiveCaretAtTypingAnchorSmooth(scrollContainer, editor) {
    if (!scrollContainer || !editor) return;
    if (isFormattedTableEditingActive(editor)) {
      cancelEditorScrollAnimation(scrollContainer);
      return;
    }
    const cmView = getCodeMirrorView(editor);
    if (cmView) {
      if (!cmView.hasFocus) {
        cancelEditorScrollAnimation(scrollContainer);
        return;
      }
      const selection = cmView.state && cmView.state.selection ? cmView.state.selection.main : null;
      if (selection && !selection.empty) {
        cancelEditorScrollAnimation(scrollContainer);
        return;
      }
    }
    const caretPos = getEditorSelectionStart(editor);
    if (typeof caretPos !== 'number') return;
    const coords = getCaretCoordinates(editor, caretPos);
    const lineHeight = getEditorLineHeight(editor);
    const caretBottomWithinContainer = editor.offsetTop + coords.top + lineHeight;
    const targetY = scrollContainer.clientHeight * (2 / 3);
    const currentY = caretBottomWithinContainer - scrollContainer.scrollTop;
    const delta = currentY - targetY;
    if (Math.abs(delta) < 1) return;
    animateEditorScrollTo(scrollContainer, scrollContainer.scrollTop + delta);
  }

  function getSlashTargetEditor() {
    if (!slashMenu.targetPane || typeof slashMenu.targetPane.getInteractionEditor !== 'function') return null;
    return slashMenu.targetPane.getInteractionEditor();
  }

  function getSlashMenuContext(text, cursorPos) {
    const source = normalizeEditorText(text);
    const safePos = Math.max(0, Math.min(source.length, Number.isFinite(cursorPos) ? cursorPos : 0));
    let tokenStart = safePos;
    while (tokenStart > 0 && !/\s/.test(source[tokenStart - 1])) tokenStart -= 1;
    if (tokenStart >= safePos || source[tokenStart] !== '/') return null;
    if (tokenStart > 0 && !/\s/.test(source[tokenStart - 1])) return null;
    const searchTerm = source.slice(tokenStart + 1, safePos);
    if (/\s/.test(searchTerm)) return null;
    return {
      searchTerm,
      startPos: tokenStart + 1,
      replaceFrom: tokenStart
    };
  }

  function getMathCommandName(command) {
    if (!command || typeof command.code !== 'string') return '';
    if (/^\\begin\{[^}]+\}$/.test(command.code)) {
      return command.code.replace(/^\\begin\{([^}]+)\}$/, '$1').toLowerCase();
    }
    return command.code.replace(/^\\/, '').toLowerCase();
  }

  function getMathCommandSearchText(command) {
    if (!command) return '';
    if (typeof command._searchText === 'string') return command._searchText;
    const parts = [
      getMathCommandName(command),
      String(command.code || ''),
      ...(Array.isArray(command.keywords) ? command.keywords : [])
    ];
    const value = parts.join(' ').trim().toLowerCase();
    command._searchText = value;
    return value;
  }

  function filterMathCommands(searchTerm) {
    const query = String(searchTerm || '').trim().toLowerCase();
    if (!query) return [];
    const ranked = [];
    for (const command of mathAutocompleteCommands) {
      const name = getMathCommandName(command);
      const haystack = getMathCommandSearchText(command);
      const keywords = Array.isArray(command.keywords) ? command.keywords : [];
      let score = Number.POSITIVE_INFINITY;
      if (name === query || String(command.code || '').toLowerCase() === query) score = 0;
      else if (name.startsWith(query)) score = 1;
      else if (String(command.code || '').toLowerCase().startsWith(`\\${query}`)) score = 2;
      else if (keywords.some((keyword) => keyword === query)) score = 3;
      else if (keywords.some((keyword) => keyword.startsWith(query))) score = 4;
      else if (name.includes(query)) score = 5;
      else if (haystack.includes(query)) score = 6;
      if (!Number.isFinite(score)) continue;
      ranked.push({
        command,
        score,
        codeLength: String(command.code || '').length
      });
    }
    ranked.sort((left, right) => (
      left.score - right.score
      || left.codeLength - right.codeLength
      || String(left.command.code || '').localeCompare(String(right.command.code || ''))
    ));
    return ranked.slice(0, 120).map((entry) => entry.command);
  }

  function renderMathPreviewHtml(command) {
    const previewSource = String((command && (command.preview || command.code)) || '').trim();
    if (!previewSource) return `<span class="math-preview-fallback">${escapeHtmlText(String(command && command.code || ''))}</span>`;
    const cacheKey = `${String(command && command.code || '')}::${previewSource}`;
    if (mathPreviewCache.has(cacheKey)) return mathPreviewCache.get(cacheKey);
    let html = `<span class="math-preview-fallback">${escapeHtmlText(String(command && command.code || ''))}</span>`;
    try {
      if (window.katex && typeof window.katex.renderToString === 'function') {
        html = window.katex.renderToString(previewSource, {
          throwOnError: false,
          strict: 'ignore',
          displayMode: /\\begin\{|\n|\\\\/.test(previewSource)
        });
      }
    } catch (_) {}
    mathPreviewCache.set(cacheKey, html);
    return html;
  }

  function findEnclosingMathMenuRegion(text, pos) {
    const source = normalizeEditorText(text);
    const safePos = Math.max(0, Math.min(source.length, Number.isFinite(pos) ? pos : 0));
    const matchers = [
      { pattern: RENDERER_BRACKET_MATH_PATTERN, openLen: 2, closeLen: 2 },
      { pattern: RENDERER_PAREN_MATH_PATTERN, openLen: 2, closeLen: 2 },
      { pattern: RENDERER_BLOCK_DOLLAR_MATH_PATTERN, openLen: 2, closeLen: 2 },
      { pattern: RENDERER_INLINE_DOLLAR_MATH_PATTERN, openLen: 1, closeLen: 1 }
    ];
    for (const matcher of matchers) {
      matcher.pattern.lastIndex = 0;
      let match;
      while ((match = matcher.pattern.exec(source))) {
        const start = match.index;
        const end = start + match[0].length;
        const contentStart = start + matcher.openLen;
        const contentEnd = end - matcher.closeLen;
        if (safePos < contentStart || safePos > contentEnd) continue;
        return { start, end, contentStart, contentEnd };
      }
    }
    return null;
  }

  function isMathAutocompleteBoundaryChar(char) {
    return !char || !/[A-Za-z0-9]/.test(char);
  }

  function getMathAutocompleteContext(text, cursorPos) {
    const source = normalizeEditorText(text);
    const safePos = Math.max(0, Math.min(source.length, Number.isFinite(cursorPos) ? cursorPos : 0));
    const region = findEnclosingMathMenuRegion(source, safePos);
    if (!region) return null;
    let searchStart = safePos;
    while (searchStart > region.contentStart && /[A-Za-z]/.test(source[searchStart - 1])) searchStart -= 1;
    if (searchStart === safePos) return null;
    let replaceFrom = searchStart;
    if (replaceFrom > region.contentStart && source[replaceFrom - 1] === '\\') replaceFrom -= 1;
    const boundaryChar = replaceFrom > region.contentStart ? source[replaceFrom - 1] : '';
    if (!isMathAutocompleteBoundaryChar(boundaryChar)) return null;
    const searchTerm = source.slice(searchStart, safePos);
    if (!searchTerm) return null;
    if (replaceFrom === searchStart && searchTerm.length < 2) return null;
    return {
      searchTerm,
      startPos: searchStart,
      replaceFrom
    };
  }

  function updateSlashMenuPosition() {
    if (!slashMenu.isOpen || !slashMenu.targetPane) return;
    const editor = getSlashTargetEditor();
    if (!editor || !hasCodeMirrorEditor(editor)) return;

    const breathingRoom = 12;
    const desiredHeight = slashMenu.el.offsetHeight || 260;
    const menuWidth = slashMenu.el.offsetWidth || 250;

    const cmView = getCodeMirrorView(editor);
    if (!cmView) return;
    const docLen = cmView.state.doc.length;
    const caretPos = Math.max(0, Math.min(docLen, Number.isFinite(slashMenu.startPos) ? slashMenu.startPos : 0));
    const caretRect = cmView.coordsAtPos(caretPos);
    if (!caretRect) return;

    const availableBelow = window.innerHeight - caretRect.bottom - breathingRoom;
    const availableAbove = caretRect.top - breathingRoom;
    const openUpward = availableBelow < Math.min(desiredHeight, 280) && availableAbove > availableBelow;
    const maxHeight = Math.max(140, Math.min(300, openUpward ? availableAbove : availableBelow));

    slashMenu.el.style.maxHeight = `${maxHeight}px`;

    let top = openUpward
      ? caretRect.top - Math.min(desiredHeight, maxHeight) - 8
      : caretRect.bottom + 8;
    let left = caretRect.left;

    const maxTop = window.innerHeight - Math.min(desiredHeight, maxHeight) - breathingRoom;
    if (top > maxTop) top = Math.max(breathingRoom, maxTop);
    if (top < breathingRoom) top = breathingRoom;
    if (left + menuWidth > window.innerWidth - breathingRoom) left = window.innerWidth - menuWidth - breathingRoom;
    if (left < breathingRoom) left = breathingRoom;

    slashMenu.el.style.top = `${top}px`;
    slashMenu.el.style.left = `${left}px`;
  }

  function closeSlashMenu() {
    slashMenu.el.hidden = true;
    slashMenu.el.classList.remove('math-mode');
    slashMenu.isOpen = false;
    slashMenu.targetPane = null;
    slashMenu.filtered = [];
    slashMenu.mode = 'slash';
    slashMenu.searchTerm = '';
  }

  document.addEventListener('scroll', () => {
    if (slashMenu.isOpen) updateSlashMenuPosition();
  }, true);
  window.addEventListener('resize', () => {
    if (slashMenu.isOpen) updateSlashMenuPosition();
  });

  function insertSlashCommand(cmd) {
    if (!slashMenu.targetPane) return;
    const pane = slashMenu.targetPane;
    slashMenu.isInserting = true;
    const editor = getSlashTargetEditor();
    if (!editor) {
      closeSlashMenu();
      slashMenu.isInserting = false;
      return;
    }
    const currentPos = getEditorSelectionStart(editor);
    const text = pane.getCurrentEditorText();
    const replaceFrom = Math.max(0, Number.isFinite(slashMenu.replaceFrom) ? slashMenu.replaceFrom : 0);
    const before = text.substring(0, replaceFrom);
    const after = text.substring(currentPos);
    const computedSnippet = typeof cmd.getSnippet === 'function'
      ? cmd.getSnippet({ pane, editor })
      : '';
    const rawSnippet = typeof computedSnippet === 'string' && computedSnippet
      ? computedSnippet
      : typeof cmd.snippet === 'string'
      ? cmd.snippet
      : typeof cmd.insert === 'string'
      ? cmd.insert
      : String(cmd.code || '');
    let snippet = rawSnippet;
    const cursorMarker = '[[cursor]]';
    let newCursorPos = before.length + snippet.length + (Number(cmd.cursorOffset) || 0);
    const markerIndex = snippet.indexOf(cursorMarker);
    if (markerIndex >= 0) {
      snippet = snippet.replace(cursorMarker, '');
      newCursorPos = before.length + markerIndex;
    }
    closeSlashMenu();
    const nextText = before + snippet + after;
    pane.commitLiveEditorText(nextText, newCursorPos, {
      focus: true,
      preserveScroll: true,
      anchorCaret: true
    });
    setTimeout(() => { slashMenu.isInserting = false; }, 100);
  }

  function renderSlashMenu(searchTerm = '') {
    const mode = slashMenu.mode === 'math' ? 'math' : 'slash';
    const query = String(searchTerm || '');
    slashMenu.searchTerm = query;
    slashMenu.filtered = mode === 'math'
      ? filterMathCommands(query)
      : slashCommands.filter((command) => command.label.toLowerCase().includes(query.toLowerCase()));
    if (slashMenu.filtered.length === 0) { closeSlashMenu(); return; }
    if (slashMenu.activeIndex >= slashMenu.filtered.length) slashMenu.activeIndex = 0;
    if (slashMenu.activeIndex < 0) slashMenu.activeIndex = slashMenu.filtered.length - 1;
    slashMenu.el.innerHTML = '';
    slashMenu.el.classList.toggle('math-mode', mode === 'math');
    slashMenu.filtered.forEach((cmd, idx) => {
      const div = document.createElement('div');
      div.className = `slash-item ${mode === 'math' ? 'math-item' : ''} ${idx === slashMenu.activeIndex ? 'active' : ''}`;
      if (mode === 'math') {
        div.innerHTML = `
          <div class="label math-preview-row">${renderMathPreviewHtml(cmd)}</div>
          <div class="desc math-code">${escapeHtmlText(String(cmd.code || ''))}</div>
        `;
      } else {
        div.innerHTML = `
          <div class="label">${escapeHtmlText(String(cmd.label || ''))}</div>
          <div class="desc">${escapeHtmlText(String(cmd.desc || ''))}</div>
        `;
      }
      div.onmousedown = (e) => { e.preventDefault(); e.stopPropagation(); insertSlashCommand(cmd); };
      slashMenu.el.appendChild(div);
    });
    slashMenu.el.hidden = false; slashMenu.isOpen = true;
    requestAnimationFrame(() => {
      const activeItem = slashMenu.el.querySelector('.slash-item.active');
      if (activeItem) activeItem.scrollIntoView({ block: 'nearest' });
    });
  }

  function applyCodeHighlighting(container) {
    if (!container || !window.hljs) return;
    container.querySelectorAll('pre code').forEach((codeEl) => {
      if (!(codeEl instanceof HTMLElement)) return;
      const classList = Array.from(codeEl.classList || []);
      const langClass = classList.find(cls => cls.startsWith('language-')) || '';
      const lang = langClass ? langClass.replace(/^language-/, '').toLowerCase() : '';
      const alreadyHighlighted = Boolean(codeEl.dataset && codeEl.dataset.notoHighlighted === '1');

      if (!alreadyHighlighted) {
        const hasHljsSpans = codeEl.querySelector('[class*="hljs-"]');
        if (!hasHljsSpans) {
          const source = codeEl.textContent || '';
          try {
            if (lang && typeof window.hljs.getLanguage === 'function' && window.hljs.getLanguage(lang)) {
              codeEl.innerHTML = window.hljs.highlight(source, { language: lang, ignoreIllegals: true }).value;
            } else {
              codeEl.innerHTML = window.hljs.highlightAuto(source).value;
            }
          } catch (e) {}
        }
        codeEl.classList.add('hljs');
        if (codeEl.dataset) codeEl.dataset.notoHighlighted = '1';
      }
    });
  }

  function getNoteDisplayName(rawName) {
    const safe = String(rawName || '').trim();
    if (!safe) return 'Untitled';
    const stripped = safe.replace(/\.md$/i, '').trim();
    return stripped || safe;
  }

  function getItemDisplayName(item) {
    if (!item || typeof item !== 'object') return 'Untitled';
    if (item.isDirectory) return String(item.name || '').trim() || 'Untitled';
    return getNoteDisplayName(item.name);
  }

  function getPathDisplayName(pathVal) {
    const safePath = String(pathVal || '').trim();
    if (!safePath) return 'Untitled';
    const leaf = safePath.split('/').pop() || safePath;
    return getNoteDisplayName(leaf);
  }

  function normalizeNoteReferenceName(value) {
    return getNoteDisplayName(value).trim().toLowerCase();
  }

  function decodeNoteReferenceFromHref(href) {
    const raw = String(href || '').trim();
    if (!raw || !raw.startsWith(NOTE_REFERENCE_SCHEME)) return '';
    try {
      return decodeURIComponent(raw.slice(NOTE_REFERENCE_SCHEME.length));
    } catch (e) {
      return raw.slice(NOTE_REFERENCE_SCHEME.length);
    }
  }

  function normalizeExternalBracketHref(value) {
    const raw = String(value || '').trim();
    if (!raw) return '';

    const normalizedMailto = raw.match(/^mailto:([^\s@]+@[^\s@]+\.[^\s@]+)$/i);
    if (normalizedMailto) return `mailto:${normalizedMailto[1]}`;

    const normalizedTel = raw.match(/^tel:(\+?[0-9()[\].\-\s]+)$/i);
    if (normalizedTel) return `tel:${normalizedTel[1].replace(/\s+/g, '')}`;

    let candidate = raw;
    if (/^www\./i.test(candidate)) candidate = `https://${candidate}`;
    if (!/^(https?:|ftp:)/i.test(candidate)) return '';

    try {
      const url = new URL(candidate);
      if (!['http:', 'https:', 'ftp:'].includes(url.protocol)) return '';
      if (!url.hostname) return '';
      return url.toString();
    } catch (e) {
      return '';
    }
  }

  function resolveNoteReferenceTargetSync(noteName) {
    const key = normalizeNoteReferenceName(noteName);
    if (!key) return null;
    const byName = noteReferenceIndexCache && noteReferenceIndexCache.byName instanceof Map
      ? noteReferenceIndexCache.byName
      : null;
    const matches = byName ? byName.get(key) : null;
    if (!matches || !matches.length) return null;
    return matches[0];
  }

  function describeBracketReference(label) {
    const noteRef = String(label || '').trim();
    if (!noteRef) return null;
    const noteTarget = resolveNoteReferenceTargetSync(noteRef);
    if (noteTarget) {
      return {
        kind: 'note',
        noteRef
      };
    }
    const href = normalizeExternalBracketHref(noteRef);
    if (!href) return null;
    return {
      kind: 'external',
      href
    };
  }

  function syncBracketReferenceResolver() {
    if (!window.NotoCodeMirror || typeof window.NotoCodeMirror.setBracketReferenceResolver !== 'function') return;
    window.NotoCodeMirror.setBracketReferenceResolver((label) => describeBracketReference(label));
  }

  function primeNoteReferenceIndex(force = false) {
    return getNoteReferenceIndex(force).catch(() => noteReferenceIndexCache.byName);
  }

  function invalidateNoteReferenceIndex() {
    noteReferenceIndexCache = {
      fetchedAt: 0,
      byName: noteReferenceIndexCache && noteReferenceIndexCache.byName instanceof Map
        ? noteReferenceIndexCache.byName
        : new Map()
    };
    noteReferenceIndexPromise = null;
  }

  async function collectMarkdownNoteEntriesForReferences() {
    if (!window.electronAPI || typeof window.electronAPI.getFiles !== 'function') return [];
    const stack = [''];
    const entries = [];
    while (stack.length > 0) {
      const current = stack.pop();
      let items = [];
      try {
        items = await window.electronAPI.getFiles(current);
      } catch (e) {
        items = [];
      }
      if (!Array.isArray(items)) continue;
      for (const item of items) {
        if (!item || typeof item.path !== 'string') continue;
        if (item.isDirectory) {
          stack.push(item.path);
          continue;
        }
        if (!String(item.path).toLowerCase().endsWith('.md')) continue;
        const fallbackName = item.path.split('/').pop() || item.path;
        entries.push({
          path: item.path,
          displayName: getNoteDisplayName(item.name || fallbackName)
        });
      }
    }
    entries.sort((a, b) => a.path.localeCompare(b.path));
    return entries;
  }

  async function getNoteReferenceIndex(force = false) {
    const now = Date.now();
    if (!force && noteReferenceIndexCache.byName.size > 0 && (now - noteReferenceIndexCache.fetchedAt) < NOTE_REFERENCE_INDEX_MAX_AGE_MS) {
      return noteReferenceIndexCache.byName;
    }
    if (!force && noteReferenceIndexPromise) return noteReferenceIndexPromise;
    noteReferenceIndexPromise = (async () => {
      const entries = await collectMarkdownNoteEntriesForReferences();
      const byName = new Map();
      entries.forEach((entry) => {
        const key = normalizeNoteReferenceName(entry.displayName);
        if (!key) return;
        if (!byName.has(key)) byName.set(key, []);
        byName.get(key).push(entry);
      });
      noteReferenceIndexCache = { fetchedAt: Date.now(), byName };
      syncBracketReferenceResolver();
      return byName;
    })();
    try {
      return await noteReferenceIndexPromise;
    } finally {
      noteReferenceIndexPromise = null;
    }
  }

  async function resolveNoteReferenceTarget(noteName) {
    const cachedTarget = resolveNoteReferenceTargetSync(noteName);
    if (cachedTarget && noteReferenceIndexCache.fetchedAt > 0) return cachedTarget;
    const key = normalizeNoteReferenceName(noteName);
    if (!key) return null;
    const byName = await getNoteReferenceIndex();
    const matches = byName.get(key);
    if (!matches || !matches.length) return null;
    return matches[0];
  }

  async function buildNoteReferencePreviewTooltipHtml(noteName) {
    const target = await resolveNoteReferenceTarget(noteName);
    if (!target) return '';
    let content = '';
    try {
      if (window.electronAPI && typeof window.electronAPI.readNote === 'function') {
        content = await window.electronAPI.readNote(target.path);
      }
    } catch (e) {}
    const html = renderMarkdownToHtml(content || '');
    return `<div class="note-ref-preview-tooltip"><div class="tab-drag-ghost-tab"><span class="tab-drag-ghost-title">${escapeHtmlText(target.displayName)}</span></div><div class="note-ref-preview-thumb"><div class="tab-drag-note-thumb"><div class="tab-drag-note-inner tab-mini-md live-markdown-editor live-rich-editor cm-host"><div class="cm-block-render">${html}</div></div></div></div></div>`;
  }

  const STORAGE_NOTE_PREVIEW_MAX_CHARS = 7000;
  const STORAGE_NOTE_PREVIEW_CACHE_MAX_ITEMS = 260;
  const STORAGE_NOTE_PREVIEW_CACHE_MAX_AGE_MS = 4000;
  const storageNotePreviewHtmlCache = new Map();
  const storageNotePreviewHtmlInflight = new Map();

  function setStorageNotePreviewCache(path, html) {
    const safePath = normalizeStoragePath(path);
    if (!safePath) return;
    if (storageNotePreviewHtmlCache.has(safePath)) storageNotePreviewHtmlCache.delete(safePath);
    storageNotePreviewHtmlCache.set(safePath, {
      html: String(html || ''),
      cachedAt: Date.now()
    });
    while (storageNotePreviewHtmlCache.size > STORAGE_NOTE_PREVIEW_CACHE_MAX_ITEMS) {
      const oldestKey = storageNotePreviewHtmlCache.keys().next().value;
      if (!oldestKey) break;
      storageNotePreviewHtmlCache.delete(oldestKey);
    }
  }

  async function getStorageNotePreviewHtml(path) {
    const safePath = normalizeStoragePath(path);
    if (!safePath) return '';
    const cached = storageNotePreviewHtmlCache.get(safePath);
    if (
      cached
      && typeof cached === 'object'
      && typeof cached.html === 'string'
      && Number.isFinite(cached.cachedAt)
      && (Date.now() - cached.cachedAt) <= STORAGE_NOTE_PREVIEW_CACHE_MAX_AGE_MS
    ) {
      return cached.html;
    }
    if (storageNotePreviewHtmlInflight.has(safePath)) return storageNotePreviewHtmlInflight.get(safePath);
    const request = (async () => {
      let content = '';
      try {
        if (window.electronAPI && typeof window.electronAPI.readNote === 'function') {
          content = await window.electronAPI.readNote(safePath);
        }
      } catch (error) {}
      const sampled = String(content || '').slice(0, STORAGE_NOTE_PREVIEW_MAX_CHARS);
      const html = renderMarkdownToHtml(sampled || '');
      setStorageNotePreviewCache(safePath, html);
      return html;
    })();
    storageNotePreviewHtmlInflight.set(safePath, request);
    try {
      return await request;
    } finally {
      storageNotePreviewHtmlInflight.delete(safePath);
    }
  }

  async function openNoteReferenceInNewTab(noteName) {
    if (isPresentationMode) return false;
    const target = await resolveNoteReferenceTarget(noteName);
    if (!target || !target.path) {
      showToast(`Note "${getNoteDisplayName(noteName)}" not found.`, 'warning');
      return false;
    }
    if (!activePane) {
      createPane();
      setupAllDividers();
    }
    const pane = activePane || panes[0];
    if (!pane) return false;
    await pane.addTab(target.path, target.displayName, null, { activate: false });
    pane.renderTabs();
    return true;
  }

  function scrollToHashTarget(href) {
    const raw = String(href || '').trim();
    if (!raw.startsWith('#')) return false;
    const hash = raw.slice(1);
    if (!hash) return false;
    const id = (() => {
      try { return decodeURIComponent(hash); } catch (e) { return hash; }
    })();
    if (!id) return false;
    const slugifyHeadingTarget = (value) => String(value || '')
      .trim()
      .toLowerCase()
      .normalize('NFKD')
      .replace(/[\u0300-\u036f]/g, '')
      .replace(/[^a-z0-9\s_-]/g, '')
      .replace(/[\s_]+/g, '-')
      .replace(/-{2,}/g, '-')
      .replace(/^-+|-+$/g, '');
    const findMarkdownHeadingOffsetBySlug = (docText, desiredSlug) => {
      const source = String(docText || '');
      if (!source || !desiredSlug) return -1;
      const lines = source.split('\n');
      let offset = 0;
      const slugCounts = new Map();
      for (const line of lines) {
        const match = line.match(/^\s{0,3}(#{1,6})\s+(.+?)\s*#*\s*$/);
        if (match) {
          const headingText = String(match[2] || '').trim();
          const base = slugifyHeadingTarget(headingText);
          if (base) {
            const seen = slugCounts.get(base) || 0;
            const slug = seen > 0 ? `${base}-${seen}` : base;
            slugCounts.set(base, seen + 1);
            if (slug === desiredSlug) return offset;
          }
        }
        offset += line.length + 1;
      }
      return -1;
    };
    const smoothScrollTargetIntoView = (targetEl, options = {}) => {
      if (!(targetEl instanceof Element)) return false;
      const margin = Number.isFinite(Number(options.yMargin)) ? Math.max(0, Number(options.yMargin)) : 56;
      const animateScrollTop = (scrollEl, targetTop) => {
        if (!scrollEl) return false;
        const startTop = Number.isFinite(scrollEl.scrollTop) ? scrollEl.scrollTop : 0;
        const delta = targetTop - startTop;
        if (Math.abs(delta) <= 1) {
          scrollEl.scrollTop = targetTop;
          return true;
        }
        const priorRaf = Number(scrollEl.__notoSmoothScrollRaf || 0);
        if (priorRaf) cancelAnimationFrame(priorRaf);
        const startTime = typeof performance !== 'undefined' && typeof performance.now === 'function'
          ? performance.now()
          : Date.now();
        const duration = Math.max(140, Math.min(320, Math.abs(delta) * 0.35));
        const easeInOut = (t) => (t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2);
        const tick = (now) => {
          if (!scrollEl || !scrollEl.isConnected) return;
          const currentTime = Number.isFinite(now) ? now : Date.now();
          const elapsed = currentTime - startTime;
          const progress = duration > 0 ? Math.max(0, Math.min(1, elapsed / duration)) : 1;
          scrollEl.scrollTop = startTop + (delta * easeInOut(progress));
          if (progress < 1) {
            scrollEl.__notoSmoothScrollRaf = requestAnimationFrame(tick);
            return;
          }
          scrollEl.scrollTop = targetTop;
          scrollEl.__notoSmoothScrollRaf = 0;
        };
        scrollEl.__notoSmoothScrollRaf = requestAnimationFrame(tick);
        return true;
      };
      let scrollParent = targetEl.parentElement;
      while (scrollParent && scrollParent !== document.body && scrollParent !== document.documentElement) {
        const style = window.getComputedStyle(scrollParent);
        const overflowY = `${style.overflowY || ''} ${style.overflow || ''}`;
        if (/(auto|scroll|overlay)/i.test(overflowY) && scrollParent.scrollHeight > scrollParent.clientHeight) {
          const parentRect = scrollParent.getBoundingClientRect();
          const targetRect = targetEl.getBoundingClientRect();
          const targetTop = Math.max(0, scrollParent.scrollTop + targetRect.top - parentRect.top - margin);
          return animateScrollTop(scrollParent, targetTop);
        }
        scrollParent = scrollParent.parentElement;
      }
      const docScroller = document.scrollingElement || document.documentElement || document.body;
      if (docScroller && typeof targetEl.getBoundingClientRect === 'function') {
        const rect = targetEl.getBoundingClientRect();
        const targetTop = Math.max(0, (Number(docScroller.scrollTop) || 0) + rect.top - margin);
        if (animateScrollTop(docScroller, targetTop)) return true;
      }
      if (typeof targetEl.scrollIntoView === 'function') {
        targetEl.scrollIntoView({ block: 'start' });
        return true;
      }
      return false;
    };

    const lookupScope = activePane && activePane.ui && activePane.ui.liveEditor
      ? activePane.ui.liveEditor
      : document;
    const cmApi = activePane && activePane.live && activePane.live.cmApi;
    const byId = document.getElementById(id);
    const byName = lookupScope.querySelector(`[name="${escapeCssSelectorValue(id)}"]`)
      || document.querySelector(`[name="${escapeCssSelectorValue(id)}"]`);
    let target = byId || byName;
    const desiredSlug = slugifyHeadingTarget(id);

    if (desiredSlug && cmApi && typeof cmApi.getDoc === 'function' && typeof cmApi.scrollToPos === 'function') {
      const offset = findMarkdownHeadingOffsetBySlug(cmApi.getDoc(), desiredSlug);
      if (offset >= 0) {
        cmApi.scrollToPos(offset, { smooth: true, yMargin: 56 });
        return true;
      }
    }

    if (!target && desiredSlug) {
      const editorHeadings = Array.from(lookupScope.querySelectorAll('.cm-line.cm-md-heading'));
      for (const line of editorHeadings) {
        const rawText = String(line.textContent || '').replace(/\u200B/g, '').trim();
        const headingText = rawText.replace(/^#{1,6}\s*/, '').trim();
        if (slugifyHeadingTarget(headingText) === desiredSlug) {
          target = line;
          break;
        }
      }
    }

    if (!target) return false;
    return smoothScrollTargetIntoView(target, { yMargin: 56 });
  }

  function isExternalHref(href) {
    return /^(https?:|mailto:|tel:|ftp:)/i.test(String(href || '').trim());
  }

  function handleRegularHtmlLink(href, event) {
    const raw = String(href || '').trim();
    if (!raw) return false;
    if (raw.startsWith('#')) {
      if (event) {
        event.preventDefault();
        event.stopPropagation();
      }
      return scrollToHashTarget(raw);
    }
    if (isExternalHref(raw)) {
      if (event) {
        event.preventDefault();
        event.stopPropagation();
      }
      if (window.electronAPI && typeof window.electronAPI.openExternal === 'function') {
        window.electronAPI.openExternal(raw);
      }
      return true;
    }
    return false;
  }

  function showTooltipNearElement(target, content) {
    if (!target || !content) return;
    if (tabPointerDrag && tabPointerDrag.active) return;
    if (tooltipHideTimer) {
      clearTimeout(tooltipHideTimer);
      tooltipHideTimer = null;
    }
    tooltipEl.innerHTML = content;
    tooltipEl.classList.toggle('multiline', /<br\s*\/?>/i.test(content));
    tooltipEl.classList.toggle('is-note-ref-preview', /note-ref-preview-tooltip/.test(String(content || '')));
    tooltipEl.style.display = 'block';
    tooltipEl.classList.add('visible');
    tooltipEl.setAttribute('aria-hidden', 'false');

    const rect = target.getBoundingClientRect();
    const ttRect = tooltipEl.getBoundingClientRect();
    const offset = 10;
    let top = rect.bottom + offset;
    if (top + ttRect.height > window.innerHeight - 8) {
      top = rect.top - ttRect.height - offset;
    }
    let left = rect.left + (rect.width - ttRect.width) / 2;
    left = Math.max(8, Math.min(left, window.innerWidth - ttRect.width - 8));
    top = Math.max(8, Math.min(top, window.innerHeight - ttRect.height - 8));

    tooltipEl.style.left = `${left}px`;
    tooltipEl.style.top = `${top}px`;

    if (tooltipMoveHandler) {
      document.removeEventListener('mousemove', tooltipMoveHandler);
      tooltipMoveHandler = null;
    }
  }

  function startNoteReferencePreview(link, noteName) {
    if (!link || !noteName) return;
    if (isPresentationMode) return;
    if (noteReferenceHoveredAnchor === link) return;
    noteReferenceHoveredAnchor = link;
    const hoverToken = ++noteReferenceHoverToken;
    buildNoteReferencePreviewTooltipHtml(noteName)
      .then((html) => {
        if (hoverToken !== noteReferenceHoverToken) return;
        if (!noteReferenceHoveredAnchor || noteReferenceHoveredAnchor !== link) return;
        if (!link.isConnected) return;
        if (!html) return;
        showTooltipNearElement(link, html);
      })
      .catch(() => {});
  }

  function stopNoteReferencePreview(link) {
    if (link && noteReferenceHoveredAnchor && noteReferenceHoveredAnchor !== link) return;
    noteReferenceHoveredAnchor = null;
    noteReferenceHoverToken += 1;
    hideTooltip();
  }

  function getLinkElementFromTarget(target) {
    const element = getEventTargetElement(target);
    if (!element || typeof element.closest !== 'function') return null;
    const link = element.closest('a[href]');
    return link instanceof HTMLElement ? link : null;
  }

  function ensureNoteReferenceGlobalHandlers() {
    if (noteReferenceGlobalListenersBound) return;
    noteReferenceGlobalListenersBound = true;

    document.addEventListener('mouseover', (event) => {
      const link = getLinkElementFromTarget(event.target);
      if (!link) return;
      const noteName = decodeNoteReferenceFromHref(link.getAttribute('href'));
      if (!noteName) return;
      startNoteReferencePreview(link, noteName);
    }, true);

    document.addEventListener('mouseout', (event) => {
      const link = getLinkElementFromTarget(event.target);
      if (!link) return;
      const noteName = decodeNoteReferenceFromHref(link.getAttribute('href'));
      if (!noteName) return;
      const related = event.relatedTarget;
      if (related instanceof Node && link.contains(related)) return;
      stopNoteReferencePreview(link);
    }, true);

    document.addEventListener('click', (event) => {
      const link = getLinkElementFromTarget(event.target);
      if (!link) return;
      const href = String(link.getAttribute('href') || '').trim();
      if (!href) return;

      // Ensure hash targets (#...) always use the smooth scroller regardless of context
      if (href.startsWith('#')) {
        try {
          event.preventDefault();
          event.stopPropagation();
        } catch (e) {}
        handleRegularHtmlLink(href, event);
        return;
      }

      const isCmRenderedLink = Boolean(link.closest('.cm-block-render'));

      const noteName = decodeNoteReferenceFromHref(href);
      if (noteName) {
        if (isCmRenderedLink) return;
        event.preventDefault();
        event.stopPropagation();
        if (!isPresentationMode) openNoteReferenceInNewTab(noteName).catch(() => {});
        return;
      }

      if (!isCmRenderedLink) return;
      handleRegularHtmlLink(href, event);
    }, true);

    window.addEventListener('noto-cm-link-activate', (event) => {
      const detail = event && event.detail ? event.detail : {};
      const href = String((detail && detail.href) || '').trim();
      if (!href) return;
      const noteName = decodeNoteReferenceFromHref(href);
      if (noteName) {
        if (!isPresentationMode) openNoteReferenceInNewTab(noteName).catch(() => {});
        return;
      }
      handleRegularHtmlLink(href);
    });
  }

  function bindNoteReferenceLink(link) {
    if (!link || !(link instanceof HTMLElement)) return;
    if (link.dataset.noteRefBound === '1') return;
    const noteName = decodeNoteReferenceFromHref(link.getAttribute('href'));
    if (!noteName) return;

    link.dataset.noteRefBound = '1';
    link.classList.add('bracket-link');
    link.classList.add('note-ref-link');
    link.setAttribute('data-custom-title', '');
  }

  function decorateRenderedMarkdown(targetElement, options = {}) {
    if (!targetElement) return;
    const interactive = options && options.interactive !== false;
    applyCodeHighlighting(targetElement);
    if (!interactive) {
      targetElement.querySelectorAll('a[href]').forEach((link) => {
        link.classList.add('is-inert-link');
        link.setAttribute('tabindex', '-1');
        link.setAttribute('aria-disabled', 'true');
      });
      targetElement.querySelectorAll('input, button, select, textarea, summary, [role="button"]').forEach((control) => {
        if (!control || !(control instanceof HTMLElement)) return;
        control.setAttribute('tabindex', '-1');
        control.setAttribute('aria-disabled', 'true');
        if ('disabled' in control) {
          try { control.disabled = true; } catch (e) {}
        }
      });
      return;
    }
    targetElement.querySelectorAll('a[href]').forEach(link => {
      const noteRefName = decodeNoteReferenceFromHref(link.getAttribute('href'));
      if (noteRefName) {
        bindNoteReferenceLink(link);
        return;
      }
      if (link.dataset.externalLinkBound === '1') return;
      link.dataset.externalLinkBound = '1';
      link.addEventListener('click', (e) => {
        handleRegularHtmlLink(link.getAttribute('href'), e);
      });
    });
  }

  function renderMarkdownToHtml(md) {
    try {
      if (window.NotoCodeMirror && typeof window.NotoCodeMirror.renderMarkdownToHtml === 'function') {
        return window.NotoCodeMirror.renderMarkdownToHtml(md || '');
      }
      return escapeHtmlText(md || '').replace(/\n/g, '<br>');
    } catch (e) {
      return escapeHtmlText(md || '');
    }
  }

  function renderMarkdownToElement(md, targetElement) {
    try {
      targetElement.innerHTML = renderMarkdownToHtml(md);
      decorateRenderedMarkdown(targetElement);
    } catch (e) {
      targetElement.textContent = md || '';
    }
  }

  function normalizeTaskListMarkup(targetElement) {
    if (!targetElement) return;
    targetElement.querySelectorAll('input.task-list-item-checkbox[type="checkbox"]').forEach((box) => {
      box.classList.add('cm-task-checkbox');
      box.removeAttribute('disabled');
      box.tabIndex = -1;
    });
    targetElement.querySelectorAll('li.task-list-item').forEach((item) => {
      const box = item.querySelector('input.task-list-item-checkbox[type="checkbox"]');
      const label = item.querySelector('label.task-list-item-label');
      if (label) label.classList.toggle('cm-task-checked-text', Boolean(box && box.checked));
    });
  }

  function renderMarkdownToMiniEditorElement(md, targetElement) {
    try {
      const html = renderMarkdownToHtml(md);
      targetElement.innerHTML = `<div class="cm-block-render">${html}</div>`;
      normalizeTaskListMarkup(targetElement);
      decorateRenderedMarkdown(targetElement);
    } catch (e) {
      targetElement.textContent = md || '';
    }
  }

  function renderMarkdownToPresentationElement(md, targetElement) {
    try {
      const html = renderMarkdownToHtml(md);
      targetElement.innerHTML = `<div class="cm-block-render">${html}</div>`;
      targetElement.querySelectorAll('input.task-list-item-checkbox[type="checkbox"]').forEach((box) => {
        box.classList.add('cm-task-checkbox');
        box.disabled = true;
        box.tabIndex = -1;
      });
      targetElement.querySelectorAll('li.task-list-item').forEach((item) => {
        const box = item.querySelector('input.task-list-item-checkbox[type="checkbox"]');
        const label = item.querySelector('label.task-list-item-label');
        if (label) label.classList.toggle('cm-task-checked-text', Boolean(box && box.checked));
      });
      if (targetElement.classList.contains('noto-pdf-export-root')) {
        targetElement.querySelectorAll('input.task-list-item-checkbox').forEach(box => {
          const span = document.createElement('span');
          span.className = 'task-list-item-checkbox' + (box.checked ? ' checked' : '');
          span.textContent = box.checked ? '☑' : '☐';
          box.parentNode.replaceChild(span, box);
        });
      }
      decorateRenderedMarkdown(targetElement);
    } catch (e) {
      targetElement.textContent = md || '';
    }
  }

  function escapeHtmlText(value) {
    return String(value || '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

