  function updatePaneEditorModeMenuAction(pane) {
    if (!pane || !pane.ui || !pane.ui.menuDropdown) return;
    const modeItem = pane.ui.menuDropdown.querySelector('.pane-menu-item[data-action="toggle-editor-mode"]');
    if (!modeItem) return;
    const tab = pane.getActiveTab ? pane.getActiveTab() : null;
    const nextModeIsRich = getTabEditorMode(tab) === 'raw';
    const nextModeLabel = nextModeIsRich ? 'Rich text' : 'Raw editor';
    const nextModeIcon = ICONS.RAW_EDITOR;
    modeItem.innerHTML = `${nextModeIcon}<span>${nextModeLabel}</span>`;
    modeItem.removeAttribute('data-custom-title');
  }

  function getFocusedCloudNoteIdForPane(pane) {
    if (!pane || typeof pane.getActiveTab !== 'function') return '';
    const tab = pane.getActiveTab();
    if (!tab || isStorageTab(tab) || isPopupTab(tab) || !tab.path) return '';
    const activeNoteId = String(tab.collabNoteId || '').trim();
    const mappedNoteId = String(getCloudNoteIdByPath(tab.path) || '').trim();
    if (!activeNoteId || !mappedNoteId || activeNoteId !== mappedNoteId) return '';
    return activeNoteId;
  }

  async function syncFocusedCloudDeleteMenuAction(pane) {
    if (!pane || !pane.ui || !pane.ui.menuDropdown || typeof pane.getActiveTab !== 'function') return;
    const deleteItem = pane.ui.menuDropdown.querySelector('.pane-menu-item[data-action="delete-cloud"]');
    if (!deleteItem) return;

    const tab = pane.getActiveTab();
    if (!tab || isStorageTab(tab) || isPopupTab(tab) || !tab.path) {
      deleteItem.hidden = true;
      return;
    }

    const mappedNoteId = String(getCloudNoteIdByPath(tab.path) || '').trim();
    if (!mappedNoteId) {
      tab.collabRole = '';
      tab.collabNoteId = '';
      tab.isReadOnly = false;
      deleteItem.hidden = true;
      return;
    }

    const knownFocusedNoteId = getFocusedCloudNoteIdForPane(pane);
    if (knownFocusedNoteId) {
      deleteItem.hidden = false;
      return;
    }

    deleteItem.hidden = true;
    const requestToken = Number(pane._cloudDeleteMenuSyncToken || 0) + 1;
    pane._cloudDeleteMenuSyncToken = requestToken;

    const authReady = await ensureCloudAuthReady();
    if (!authReady.ok || !window.cloudAPI || typeof window.cloudAPI.getNote !== 'function') return;

    let result = null;
    try {
      result = await window.cloudAPI.getNote({ noteId: mappedNoteId });
    } catch (error) {
      return;
    }

    const stillActiveTab = pane.getActiveTab ? pane.getActiveTab() : null;
    if (
      Number(pane._cloudDeleteMenuSyncToken || 0) !== requestToken
      || !stillActiveTab
      || stillActiveTab.path !== tab.path
    ) {
      return;
    }

    if (result && result.success && result.note) {
      tab.collabNoteId = mappedNoteId;
      deleteItem.hidden = false;
      return;
    }

    if (isMissingCloudNote(result)) {
      detachCloudNoteByPath(tab.path);
      deleteItem.hidden = true;
    }
  }

  function updatePaneUploadMenuAction(pane) {
    if (!pane || !pane.ui || !pane.ui.menuDropdown) return;
    const deleteItem = pane.ui.menuDropdown.querySelector('.pane-menu-item[data-action="delete-cloud"]');
    if (!deleteItem) return;
    deleteItem.hidden = !getFocusedCloudNoteIdForPane(pane);
  }

