    async function persistAppBehaviorSettings(partialSettings = {}, options = {}) {
      const toggleInput = options && options.input instanceof HTMLInputElement ? options.input : null;
      const partialKeys = Object.keys(partialSettings || {});
      if (appBehaviorUpdateInFlight) {
        if (toggleInput && partialKeys.length === 1) {
          toggleInput.checked = Boolean(settingsState.appBehavior[partialKeys[0]]);
        }
        return;
      }
      const previous = { ...settingsState.appBehavior };
      settingsState.appBehavior = {
        ...settingsState.appBehavior,
        ...partialSettings
      };
      appBehaviorUpdateInFlight = true;
      if (toggleInput) toggleInput.disabled = true;
      try {
        if (!window.api || typeof window.api.setAppBehaviorSettings !== 'function') {
          throw new Error('Settings API unavailable.');
        }
        const result = await window.api.setAppBehaviorSettings(partialSettings);
        if (!result || !result.success) {
          throw new Error((result && result.error) || 'Failed to save settings.');
        }
        settingsState.appBehavior = normalizeAppBehaviorResult(result);
        if (toggleInput && partialKeys.length === 1) {
          toggleInput.checked = Boolean(settingsState.appBehavior[partialKeys[0]]);
        }
      } catch (error) {
        settingsState.appBehavior = previous;
        if (toggleInput && partialKeys.length === 1) {
          toggleInput.checked = Boolean(previous[partialKeys[0]]);
        }
        showToast(error && error.message ? error.message : 'Failed to save settings.', 'warning');
      } finally {
        appBehaviorUpdateInFlight = false;
        if (toggleInput) {
          const isStartupToggle = partialKeys.includes('openOnSystemStart');
          toggleInput.disabled = isStartupToggle && !settingsState.appBehavior.supportsOpenOnSystemStart;
        }
      }
    }

    function createToastDurationControl() {
      const wrap = document.createElement('div');
      wrap.className = 'settings-number-wrap';
      const input = document.createElement('input');
      input.type = 'number';
      input.className = 'settings-number-input';
      input.min = String(TOAST_MIN_DURATION_MS);
      input.max = String(TOAST_MAX_DURATION_MS);
      input.step = '100';
      input.value = String(settingsState.toastSettings.durationMs);
      input.setAttribute('aria-label', 'Notification duration in milliseconds');
      const suffix = document.createElement('span');
      suffix.className = 'settings-number-suffix';
      suffix.textContent = 'ms';
      const commit = () => {
        settingsState.toastSettings = setToastSettings({
          ...settingsState.toastSettings,
          durationMs: input.value
        });
        input.value = String(settingsState.toastSettings.durationMs);
      };
      input.addEventListener('change', commit);
      input.addEventListener('blur', commit);
      input.addEventListener('keydown', (event) => {
        if (event.key === 'Enter') {
          event.preventDefault();
          commit();
          input.blur();
        }
      });
      wrap.append(input, suffix);
      return wrap;
    }

    function createShortcutInput(shortcutKey) {
      const input = document.createElement('input');
      input.type = 'text';
      input.readOnly = true;
      input.className = 'settings-shortcut-input';
      const placeholderValue = 'Hold up to 3 keys';
      input.value = getAppShortcut(shortcutKey);
      input.setAttribute('data-custom-title', 'Hold up to 3 keys, then release to save');
      let isCapturing = false;
      let captureTokens = [];
      const activeCaptureTokens = new Set();
      const restoreAssignedValue = () => {
        input.value = getAppShortcut(shortcutKey);
      };
      const clearCaptureState = () => {
        captureTokens = [];
        activeCaptureTokens.clear();
      };
      const renderCapturePreview = () => {
        input.value = formatShortcutCaptureTokens(captureTokens) || placeholderValue;
      };
      const commitCapturedShortcut = () => {
        if (!hasShortcutPrimaryKey(captureTokens)) return false;
        const combo = formatShortcutCaptureTokens(captureTokens);
        if (!combo) return false;
        setAppShortcut(shortcutKey, combo);
        stopCapture(true);
        return true;
      };
      const startCapture = () => {
        isCapturing = true;
        isShortcutCaptureActive = true;
        input.classList.add('is-capturing');
        clearCaptureState();
        renderCapturePreview();
      };
      const stopCapture = (restore = true) => {
        isCapturing = false;
        isShortcutCaptureActive = false;
        input.classList.remove('is-capturing');
        clearCaptureState();
        if (restore) restoreAssignedValue();
      };
      input.addEventListener('focus', () => {
        if (!isCapturing) startCapture();
      });
      input.addEventListener('blur', () => {
        stopCapture(true);
      });
      input.addEventListener('mousedown', (event) => {
        if (document.activeElement === input && isCapturing) {
          event.preventDefault();
        }
      });
      input.addEventListener('keydown', (event) => {
        if (event.key === 'Tab') return;
        event.preventDefault();
        event.stopPropagation();
        if (typeof event.stopImmediatePropagation === 'function') event.stopImmediatePropagation();
        if (!isCapturing) startCapture();
        if (event.key === 'Escape') {
          stopCapture(true);
          input.blur();
          return;
        }
        if (event.key === 'Enter') {
          stopCapture(true);
          input.blur();
          return;
        }
        if (
          (event.key === 'Backspace' || event.key === 'Delete')
          && !event.ctrlKey && !event.metaKey && !event.altKey && !event.shiftKey
        ) {
          setAppShortcut(shortcutKey, APP_SHORTCUT_DEFAULTS[shortcutKey]);
          stopCapture(true);
          return;
        }
        const keyToken = normalizeShortcutKeyToken(event.key);
        if (!keyToken) return;
        activeCaptureTokens.add(keyToken);
        if (!captureTokens.includes(keyToken) && captureTokens.length < SHORTCUT_CAPTURE_MAX_KEYS) {
          captureTokens = captureTokens.concat(keyToken);
        }
        renderCapturePreview();
      });
      input.addEventListener('keyup', (event) => {
        if (!isCapturing || event.key === 'Tab') return;
        event.preventDefault();
        event.stopPropagation();
        if (typeof event.stopImmediatePropagation === 'function') event.stopImmediatePropagation();
        const keyToken = normalizeShortcutKeyToken(event.key);
        if (keyToken) activeCaptureTokens.delete(keyToken);
        if (activeCaptureTokens.size > 0) return;
        if (commitCapturedShortcut()) return;
        clearCaptureState();
        renderCapturePreview();
      });
      return input;
    }

    function createTabIconModeControl() {
      const wrap = document.createElement('div');
      wrap.className = 'settings-choice-group';
      wrap.setAttribute('role', 'radiogroup');
      wrap.setAttribute('aria-label', 'Tab note icon display');
      const options = [
        { id: 'off', label: 'Off' },
        { id: 'modified', label: 'Modified only' },
        { id: 'all', label: 'All notes' }
      ];
      options.forEach((option) => {
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'settings-choice-btn';
        const isActive = settingsState.tabIconMode === option.id;
        btn.classList.toggle('is-active', isActive);
        btn.setAttribute('aria-pressed', isActive ? 'true' : 'false');
        btn.setAttribute('role', 'radio');
        btn.setAttribute('aria-checked', isActive ? 'true' : 'false');
        btn.textContent = option.label;
        btn.onclick = () => {
          if (settingsState.tabIconMode === option.id) return;
          settingsState.tabIconMode = setTabIconMode(option.id);
          renderSettingsCategoryContent();
        };
        wrap.appendChild(btn);
      });
      return wrap;
    }

    function createProfileColorControl(ownerEmail, initial, options = {}) {
      const wrap = document.createElement('div');
      wrap.className = 'settings-account-color-wrap';
      const isHeroMode = Boolean(options && options.hero);
      if (isHeroMode) wrap.classList.add('is-hero');

      const button = document.createElement('button');
      button.type = 'button';
      button.className = 'settings-account-color-btn';
      if (isHeroMode) button.classList.add('is-hero');

      const preview = document.createElement('span');
      preview.className = 'settings-account-avatar-preview';
      preview.textContent = initial || 'U';
      if (isHeroMode) preview.classList.add('is-hero');

      const pen = document.createElement('span');
      pen.className = 'settings-account-color-pen';
      pen.innerHTML = `<svg width="13" height="13" viewBox="0 0 24 24" aria-hidden="true"><path fill="currentColor" d="M22 7.24a1 1 0 0 0-.29-.71l-4.24-4.24a1 1 0 0 0-.71-.29a1 1 0 0 0-.71.29l-2.83 2.83L2.29 16.05a1 1 0 0 0-.29.71V21a1 1 0 0 0 1 1h4.24a1 1 0 0 0 .76-.29l10.87-10.93L21.71 8a1.2 1.2 0 0 0 .22-.33a1 1 0 0 0 0-.24a.7.7 0 0 0 0-.14ZM6.83 20H4v-2.83l9.93-9.93l2.83 2.83ZM18.17 8.66l-2.83-2.83l1.42-1.41l2.82 2.82Z"/></svg>`;
      if (isHeroMode) pen.classList.add('is-hero');

      button.append(preview, pen);

      const popover = document.createElement('div');
      popover.className = 'settings-account-color-popover';
      popover.hidden = true;
      if (isHeroMode) popover.classList.add('is-hero');

      const grid = document.createElement('div');
      grid.className = 'settings-account-color-grid';
      popover.appendChild(grid);

      const ownerKey = String(ownerEmail || getProfileColorOwnerEmail()).trim().toLowerCase() || 'guest';
      let activeHue = getProfileHue(ownerKey);

      const applyPreview = (hueValue) => {
        const colors = buildProfileColors(hueValue);
        preview.style.backgroundColor = colors.bg;
        preview.style.color = colors.fg;
        button.style.color = colors.fg;
        button.style.setProperty('--settings-profile-accent', colors.fg);
      };

      const updateActiveSwatches = () => {
        const swatches = Array.from(grid.querySelectorAll('.settings-account-color-swatch'));
        const rootStyles = window.getComputedStyle(document.documentElement);
        const surfaceColor = (rootStyles.getPropertyValue('--bg') || '').trim() || '#ffffff';
        swatches.forEach((swatchEl) => {
          const swatchHue = Number(swatchEl.dataset.hue);
          const isActive = Number.isFinite(swatchHue) && swatchHue === activeHue;
          const ringColor = String(swatchEl.dataset.ringColor || '#000000');
          swatchEl.classList.toggle('active', isActive);
          swatchEl.setAttribute('aria-pressed', isActive ? 'true' : 'false');
          swatchEl.style.boxShadow = isActive
            ? `0 0 0 1px ${surfaceColor}, 0 0 0 2px ${ringColor}`
            : '';
        });
      };

      accountColorHues.forEach((hueValue) => {
        const swatch = document.createElement('button');
        swatch.type = 'button';
        swatch.className = 'settings-account-color-swatch';
        swatch.dataset.hue = String(hueValue);
        const swatchColors = buildProfileColors(hueValue);
        swatch.style.backgroundColor = swatchColors.bg;
        swatch.style.borderColor = swatchColors.fg;
        swatch.dataset.ringColor = swatchColors.fg;
        swatch.setAttribute('aria-label', `Profile color ${hueValue}`);
        swatch.onclick = (event) => {
          event.preventDefault();
          event.stopPropagation();
          activeHue = hueValue;
          setProfileHue(ownerKey, hueValue);
          applyProfileColors(ownerKey);
          applyPreview(activeHue);
          updateActiveSwatches();
          popover.hidden = true;
        };
        grid.appendChild(swatch);
      });

      button.onclick = (event) => {
        event.preventDefault();
        event.stopPropagation();
        const shouldOpen = popover.hidden;
        closeOpenColorPopovers();
        popover.hidden = !shouldOpen;
      };

      applyPreview(activeHue);
      updateActiveSwatches();
      wrap.append(button, popover);
      return wrap;
    }

