  function setCenteredPopupOpen(popupEl, isOpen) {
    if (!popupEl) return;
    if (popupEl.__hideTimer) {
      clearTimeout(popupEl.__hideTimer);
      popupEl.__hideTimer = null;
    }
    if (isOpen) {
      popupEl.hidden = false;
      popupEl.setAttribute('aria-hidden', 'false');
      requestAnimationFrame(() => {
        popupEl.classList.add('is-open');
      });
      return;
    }
    popupEl.classList.remove('is-open');
    popupEl.setAttribute('aria-hidden', 'true');
    popupEl.__hideTimer = setTimeout(() => {
      if (!popupEl.classList.contains('is-open')) popupEl.hidden = true;
      popupEl.__hideTimer = null;
    }, 240);
  }

  function setCenteredPopupWidth(popupEl, options = {}) {
    if (!popupEl) return;
    const viewportWidth = Math.max(320, Math.floor(window.innerWidth || 0));
    const maxWidth = Math.max(360, Number(options.maxWidth) || SEARCH_OPEN_MAX_WIDTH_PX);
    const minWidth = Math.max(360, Number(options.minWidth) || 420);
    const widthRatio = Math.min(0.92, Math.max(0.4, Number(options.widthRatio) || 0.56));
    const preferredWidth = Math.min(
      maxWidth,
      Math.max(minWidth, Math.floor(viewportWidth * widthRatio))
    );
    const clampedWidth = Math.max(280, Math.min(preferredWidth, viewportWidth - 24));
    popupEl.style.setProperty('--titlebar-search-open-w', `${clampedWidth}px`);
  }

