  let searchIndexEntries = [];
  let searchIndexTimestamp = 0;
  let searchIndexPromise = null;
  let searchIndexRefreshTimer = null;
  let searchIndexRefreshChain = Promise.resolve();
  let searchSelectionIndex = -1;
  const SEARCH_INDEX_TTL = 1000 * 60 * 3;
  const QUICK_CREATE_FOLDER_CACHE_TTL_MS = 1000 * 20;
  const SEARCH_OPEN_MAX_WIDTH_PX = 640;
  const NOTE_FIND_MAX_MARKERS = 600;
  const SEARCH_APP_ICON = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><rect x="4" y="4" width="16" height="16" rx="3"></rect><path d="M8.5 12h7M12 8.5v7"></path></svg>`;

  function escapeRegExp(text) {
    return String(text || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  function getSearchTerms(query) {
    const raw = String(query || '').trim();
    const normalized = (raw.startsWith('/') ? raw.slice(1).trim() : raw).toLowerCase();
    if (!normalized) return [];
    return [normalized];
  }

  function getQuickCreateSearchNoteName(query) {
    const raw = String(query || '').trim();
    if (!raw.startsWith('/')) return '';
    const withoutSlash = raw.slice(1).trim();
    if (!withoutSlash) return '';
    const safeName = withoutSlash
      .replace(/[\\/]+/g, ' ')
      .replace(/\s+/g, ' ')
      .replace(/\.md$/i, '')
      .trim();
    return safeName;
  }

  function highlightSearchTerms(text, terms) {
    const escaped = escapeHtmlText(String(text || ''));
    if (!escaped) return escaped;
    if (!Array.isArray(terms) || terms.length === 0) return escaped;
    const parts = Array.from(new Set(
      terms
        .map((term) => String(term || '').trim())
        .filter(Boolean)
    ))
      .sort((a, b) => b.length - a.length)
      .map((term) => escapeRegExp(escapeHtmlText(term)));
    if (!parts.length) return escaped;
    const matcher = new RegExp(`(${parts.join('|')})`, 'gi');
    return escaped.replace(matcher, '<mark>$1</mark>');
  }

  function getSearchResultItems() {
    if (!searchUI.list) return [];
    return Array.from(searchUI.list.querySelectorAll('li[data-search-result="1"]'));
  }

  function setSearchSelection(index, options = {}) {
    const items = getSearchResultItems();
    if (!items.length) {
      searchSelectionIndex = -1;
      return;
    }
    const normalized = ((Number(index) % items.length) + items.length) % items.length;
    searchSelectionIndex = normalized;
    items.forEach((item, itemIndex) => {
      item.classList.toggle('selected', itemIndex === normalized);
    });
    if (options.scrollIntoView !== false) {
      const target = items[normalized];
      if (target && typeof target.scrollIntoView === 'function') {
        target.scrollIntoView({ block: 'nearest' });
      }
    }
  }

  function stepSearchSelection(delta) {
    const items = getSearchResultItems();
    if (!items.length) {
      searchSelectionIndex = -1;
      return;
    }
    if (searchSelectionIndex < 0) {
      setSearchSelection(delta >= 0 ? 0 : (items.length - 1));
      return;
    }
    setSearchSelection(searchSelectionIndex + delta);
  }

  function updateSearchClearButtonVisibility() {
    if (!searchUI.clearBtn || !searchUI.input) return;
    const hasValue = Boolean(searchUI.input.value);
    searchUI.clearBtn.disabled = !hasValue;
    searchUI.clearBtn.classList.toggle('is-empty', !hasValue);
  }

  async function getAllEntriesRecursively(dirPath) {
    let results = [];
    try {
      const items = await window.electronAPI.getFiles(dirPath);
      for (const item of items) {
        results.push(item);
        if (item && item.isDirectory) {
          results = results.concat(await getAllEntriesRecursively(item.path));
        }
      }
    } catch (e) {}
    return results;
  }

  async function buildQuickCreateFolderEntries() {
    const entries = await getAllEntriesRecursively('');
    return entries
      .filter((item) => item && item.isDirectory)
      .map((item) => {
        const folderPath = normalizeStoragePath(item && item.path);
        if (!folderPath) return null;
        const folderName = String(item && item.name ? item.name : (folderPath.split('/').pop() || '')).trim();
        return {
          path: folderPath,
          pathLower: folderPath.toLowerCase(),
          name: folderName || folderPath.split('/').pop() || folderPath,
          nameLower: (folderName || folderPath).toLowerCase()
        };
      })
      .filter(Boolean)
      .sort((left, right) => left.path.localeCompare(right.path));
  }

  async function getQuickCreateFolderEntries(options = {}) {
    const force = Boolean(options && options.force);
    const hasFreshCache = (Date.now() - Number(quickCreateFolderCache.ts || 0)) < QUICK_CREATE_FOLDER_CACHE_TTL_MS;
    if (!force && quickCreateFolderCache.pending) {
      try {
        return await quickCreateFolderCache.pending;
      } catch (error) {}
    }
    if (!force && hasFreshCache && Array.isArray(quickCreateFolderCache.entries)) {
      return quickCreateFolderCache.entries.slice();
    }
    const request = (async () => {
      try {
        const entries = await buildQuickCreateFolderEntries();
        quickCreateFolderCache = {
          ts: Date.now(),
          entries: Array.isArray(entries) ? entries : [],
          pending: null
        };
        return quickCreateFolderCache.entries.slice();
      } finally {
        if (quickCreateFolderCache.pending === request) quickCreateFolderCache.pending = null;
      }
    })();
    quickCreateFolderCache.pending = request;
    return request;
  }

  function getQuickCreateFolderTerms(query) {
    const raw = String(query || '').trim().toLowerCase();
    if (!raw) return [];
    return Array.from(new Set([
      raw,
      ...raw.split(/\s+/).filter(Boolean)
    ]));
  }

  function scoreQuickCreateFolderEntry(entry, query, terms) {
    if (!entry) return null;
    const safeQuery = String(query || '').trim().toLowerCase();
    const safeTerms = Array.isArray(terms) ? terms.filter(Boolean) : [];
    if (!safeQuery && safeTerms.length === 0) return null;
    const nameLower = String(entry.nameLower || '').toLowerCase();
    const pathLower = String(entry.pathLower || '').toLowerCase();
    let score = 0;

    if (safeQuery) {
      if (pathLower === safeQuery) score += 132;
      else if (pathLower.startsWith(safeQuery)) score += 88;
      else if (pathLower.includes(safeQuery)) score += 62;

      if (nameLower === safeQuery) score += 120;
      else if (nameLower.startsWith(safeQuery)) score += 92;
      else if (nameLower.includes(safeQuery)) score += 74;
    }

    for (const term of safeTerms) {
      const nameIndex = nameLower.indexOf(term);
      const pathIndex = pathLower.indexOf(term);
      if (nameIndex === -1 && pathIndex === -1) return null;
      if (nameIndex === 0) score += 36;
      else if (nameIndex > 0) score += 28;
      if (pathIndex === 0) score += 24;
      else if (pathIndex > 0) score += 18;
    }

    return {
      entry,
      score
    };
  }

  function isMarkdownNotePath(pathValue) {
    const safePath = normalizeStoragePath(pathValue || '');
    return Boolean(safePath && safePath.toLowerCase().endsWith('.md'));
  }

  async function computeLocalNotesUsageSummary() {
    try {
      const entries = await getAllEntriesRecursively('');
      let totalBytes = 0;
      let noteCount = 0;
      for (const entry of entries) {
        if (!entry || entry.isDirectory) continue;
        if (!isMarkdownNotePath(entry.path || entry.name || '')) continue;
        noteCount += 1;
        const bytes = Number(entry.sizeBytes);
        if (Number.isFinite(bytes) && bytes >= 0) {
          totalBytes += bytes;
          continue;
        }
        const fallbackBytes = Number(entry.size);
        if (Number.isFinite(fallbackBytes) && fallbackBytes >= 0) {
          totalBytes += fallbackBytes;
        }
      }
      return {
        sizeBytes: Math.max(0, Math.round(totalBytes)),
        noteCount: Math.max(0, Math.round(noteCount))
      };
    } catch (error) {
      return {
        sizeBytes: Math.max(0, Number(localNotesUsageCache.sizeBytes) || 0),
        noteCount: Math.max(0, Number(localNotesUsageCache.noteCount) || 0)
      };
    }
  }

  async function getLocalNotesUsageSummary(options = {}) {
    const force = Boolean(options && options.force);
    const now = Date.now();
    if (!force && localNotesUsageCache.pending) {
      try {
        return await localNotesUsageCache.pending;
      } catch (error) {}
    }
    const hasFreshCache = (now - Number(localNotesUsageCache.ts || 0)) < LOCAL_NOTES_USAGE_CACHE_TTL_MS;
    if (!force && hasFreshCache) {
      return {
        sizeBytes: Math.max(0, Number(localNotesUsageCache.sizeBytes) || 0),
        noteCount: Math.max(0, Number(localNotesUsageCache.noteCount) || 0)
      };
    }
    const request = (async () => {
      try {
        const summary = await computeLocalNotesUsageSummary();
        localNotesUsageCache = {
          ts: Date.now(),
          sizeBytes: Math.max(0, Number(summary.sizeBytes) || 0),
          noteCount: Math.max(0, Number(summary.noteCount) || 0),
          pending: null
        };
        return {
          sizeBytes: localNotesUsageCache.sizeBytes,
          noteCount: localNotesUsageCache.noteCount
        };
      } catch (error) {
        return {
          sizeBytes: Math.max(0, Number(localNotesUsageCache.sizeBytes) || 0),
          noteCount: Math.max(0, Number(localNotesUsageCache.noteCount) || 0)
        };
      } finally {
        if (localNotesUsageCache.pending === request) localNotesUsageCache.pending = null;
      }
    })();
    localNotesUsageCache.pending = request;
    return request;
  }

  function createSearchEntry(item, content = '') {
    const safePath = typeof item.path === 'string' ? item.path : '';
    const safeName = typeof item.name === 'string' ? item.name : (safePath.split('/').pop() || '');
    const displayName = item.isDirectory ? safeName : safeName.replace(/\.md$/i, '');
    const safeContent = item.isDirectory ? '' : normalizeEditorText(content || '');
    return {
      type: item.isDirectory ? 'folder' : 'file',
      path: safePath,
      name: safeName,
      displayName,
      pathLower: safePath.toLowerCase(),
      nameLower: safeName.toLowerCase(),
      displayNameLower: displayName.toLowerCase(),
      content: safeContent,
      contentLower: safeContent.toLowerCase()
    };
  }

  function createAppSearchEntry(options = {}) {
    const label = String(options.name || '').trim();
    if (!label) return null;
    const location = String(options.path || 'Application').trim() || 'Application';
    const keywordText = Array.isArray(options.keywords)
      ? options.keywords.map((item) => String(item || '').trim()).filter(Boolean).join(' ')
      : String(options.keywords || '').trim();
    const detailsText = String(options.content || '').trim();
    const searchableContent = normalizeEditorText([detailsText, keywordText].filter(Boolean).join(' '));
    const payload = (options.payload && typeof options.payload === 'object') ? { ...options.payload } : null;
    return {
      type: 'app',
      path: location,
      name: label,
      displayName: label,
      pathLower: location.toLowerCase(),
      nameLower: label.toLowerCase(),
      displayNameLower: label.toLowerCase(),
      content: searchableContent,
      contentLower: searchableContent.toLowerCase(),
      searchAction: String(options.action || '').trim(),
      searchPayload: payload,
      searchIcon: typeof options.icon === 'string' ? options.icon : ''
    };
  }

  function formatSearchTimestamp(ts) {
    const value = Number(ts);
    if (!Number.isFinite(value)) return '';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleString();
  }

