  function refreshSearchDynamicEntries() {
    const staticEntries = Array.isArray(searchIndexEntries)
      ? searchIndexEntries.filter((entry) => entry && entry.type !== 'app')
      : [];
    const appEntries = buildAppSearchIndexEntries();
    searchIndexEntries = staticEntries.concat(appEntries);
  }

  function queueSearchIndexRefresh(options = {}) {
    const delayMs = Math.max(0, Number(options && options.delayMs) || 0);
    searchIndexTimestamp = 0;
    quickCreateFolderCache.ts = 0;
    if (searchIndexRefreshTimer) clearTimeout(searchIndexRefreshTimer);
    searchIndexRefreshTimer = setTimeout(() => {
      searchIndexRefreshTimer = null;
      searchIndexRefreshChain = searchIndexRefreshChain
        .then(async () => {
          await ensureSearchIndex(true);
          refreshSearchDynamicEntries();
          if (isSearchPanelOpen()) {
            renderSearchResults(searchUI.input ? (searchUI.input.value || '') : '');
          }
        })
        .catch(() => {});
    }, delayMs);
  }

  function getSearchActiveNoteContext() {
    if (activePane && typeof activePane.getActiveTab === 'function') {
      const tab = activePane.getActiveTab();
      if (tab && tab.path) return { pane: activePane, tab };
    }
    for (const pane of panes) {
      if (!pane || typeof pane.getActiveTab !== 'function') continue;
      const tab = pane.getActiveTab();
      if (tab && tab.path) return { pane, tab };
    }
    return null;
  }

  async function openSearchAppEntry(entry) {
    const action = String(entry && entry.searchAction ? entry.searchAction : '').trim();
    const payload = (entry && entry.searchPayload && typeof entry.searchPayload === 'object')
      ? entry.searchPayload
      : {};
    const requireNoteContext = (label) => {
      const ctx = getSearchActiveNoteContext();
      if (ctx) return ctx;
      showToast(`Open a note before using "${label}".`, 'info', 2200);
      return null;
    };

    switch (action) {
      case 'settings-category':
        await showSettingsModal({ category: payload.category });
        return;
      case 'open-settings':
        await showSettingsModal();
        return;
      case 'open-bin':
        await showBinModal();
        return;
      case 'open-collaborations':
        await openStorageCollaborationsDropdown(activePane || null, { forceRefresh: true });
        return;
      case 'open-logout':
        showLogoutModal();
        return;
      case 'open-delete-account':
        showDeleteAccountModal();
        return;
      case 'open-create-item':
        await showCreateItemModal();
        return;
      case 'quick-create-note':
        await handleQuickCreateNoteFromSearch(payload.noteName || '');
        return;
      case 'open-cloud-note':
        if (payload.noteId) {
          await openCloudNoteById(payload.noteId);
          return;
        }
        await openStorageCollaborationsDropdown(activePane || null, { forceRefresh: true });
        return;
      case 'open-manage-presentation': {
        const context = requireNoteContext('Manage presentation');
        if (!context) return;
        if (livePresentation.isOpen) showManagePresentationModal(context.pane, context.tab);
        else showDisplayPicker(context.pane, context.tab);
        return;
      }
      case 'open-collaborate-note': {
        const context = requireNoteContext('Collaborate note');
        if (!context) return;
        await showCollaborateModal(context.pane, context.tab);
        return;
      }
      case 'open-delete-cloud-note': {
        const context = requireNoteContext('Delete from cloud');
        if (!context) return;
        await showDeleteCloudNoteModal(context.pane, context.tab);
        return;
      }
      default:
        await showSettingsModal();
    }
  }

  function getSearchResultIcon(entry) {
    if (!entry) return ICONS.FILE;
    if (entry.type === 'folder') return ICONS.FOLDER;
    if (entry.type === 'app') return entry.searchIcon || SEARCH_APP_ICON;
    return ICONS.FILE;
  }

  async function buildSearchIndexEntries() {
    const [flat, appEntries] = await Promise.all([
      getAllEntriesRecursively(''),
      Promise.resolve(buildAppSearchIndexEntries())
    ]);
    const entries = [];
    for (const item of flat) {
      if (!item || typeof item.path !== 'string') continue;
      if (item.isDirectory) {
        entries.push(createSearchEntry(item));
        continue;
      }
      let content = '';
      try {
        const raw = await window.electronAPI.readNote(item.path);
        if (typeof raw === 'string') content = raw;
      } catch (e) {}
      entries.push(createSearchEntry(item, content));
    }
    if (Array.isArray(appEntries) && appEntries.length) {
      entries.push(...appEntries);
    }
    return entries;
  }

  async function ensureSearchIndex(force = false) {
    const isFresh = searchIndexEntries.length > 0 && (Date.now() - searchIndexTimestamp) < SEARCH_INDEX_TTL;
    if (!force && isFresh) return searchIndexEntries;
    if (searchIndexPromise && !force) return searchIndexPromise;
    searchIndexPromise = (async () => {
      const nextEntries = await buildSearchIndexEntries();
      searchIndexEntries = Array.isArray(nextEntries) ? nextEntries : [];
      searchIndexTimestamp = Date.now();
      return searchIndexEntries;
    })();
    try {
      return await searchIndexPromise;
    } finally {
      searchIndexPromise = null;
    }
  }

  function scoreSearchEntry(entry, terms) {
    let score = 0;
    let firstContentIndex = -1;
    for (const term of terms) {
      let matched = false;
      const displayNameIdx = entry.displayNameLower ? entry.displayNameLower.indexOf(term) : -1;
      if (displayNameIdx !== -1) {
        score += displayNameIdx === 0 ? 76 : 64;
        matched = true;
      }
      const nameIdx = entry.nameLower ? entry.nameLower.indexOf(term) : -1;
      if (nameIdx !== -1) {
        score += nameIdx === 0 ? 70 : 58;
        matched = true;
      }
      const pathIdx = entry.pathLower ? entry.pathLower.indexOf(term) : -1;
      if (pathIdx !== -1) {
        score += pathIdx === 0 ? 36 : 26;
        matched = true;
      }
      if (entry.contentLower) {
        const contentIdx = entry.contentLower.indexOf(term);
        if (contentIdx !== -1) {
          score += entry.type === 'app' ? 30 : 24;
          if (firstContentIndex < 0 || contentIdx < firstContentIndex) firstContentIndex = contentIdx;
          matched = true;
        }
      }
      if (!matched) return null;
    }
    score += entry.type === 'folder' ? 5 : 0;
    score += entry.type === 'app' ? 9 : 0;
    return { entry, score, firstContentIndex };
  }

  function buildSearchSnippet(entry, hit, terms) {
    if (!entry || entry.type === 'folder' || !entry.content || !hit || hit.firstContentIndex < 0) return '';
    const queryTerms = Array.isArray(terms) ? terms.filter(Boolean) : [];
    const firstTerm = queryTerms[0] || '';
    const start = Math.max(0, hit.firstContentIndex - 46);
    const end = Math.min(entry.content.length, hit.firstContentIndex + firstTerm.length + 88);
    let snippet = entry.content.slice(start, end).replace(/\s+/g, ' ').trim();
    if (!snippet) return '';
    if (start > 0) snippet = `...${snippet}`;
    if (end < entry.content.length) snippet = `${snippet}...`;
    return highlightSearchTerms(snippet, queryTerms);
  }

  function appendSearchResultListItem(hit, query) {
    if (!searchUI.list || !hit || !hit.entry) return;
    const entry = hit.entry;
    const terms = getSearchTerms(query);
    const li = document.createElement('li');
    li.setAttribute('data-search-result', '1');
    li.setAttribute('tabindex', '-1');
    const rawPath = String(entry.path || '');
    const displayPath = rawPath.length > 56 ? `...${rawPath.slice(-56)}` : rawPath;
    const icon = getSearchResultIcon(entry);
    const snippet = buildSearchSnippet(entry, hit, terms);
    const nameHtml = highlightSearchTerms(entry.displayName || entry.name, terms);
    const pathHtml = displayPath ? highlightSearchTerms(displayPath, terms) : '';
    li.innerHTML = `
      <div class="search-result-main">
        ${icon}
        <span class="search-result-name">${nameHtml}</span>
        ${pathHtml ? `<span class="path-sub">${pathHtml}</span>` : ''}
      </div>
      ${snippet ? `<div class="search-result-snippet">${snippet}</div>` : ''}
    `;
    li.onclick = async () => {
      await openSearchResult(hit, query);
    };
    li.onmouseenter = () => {
      const items = getSearchResultItems();
      const idx = items.indexOf(li);
      if (idx >= 0) setSearchSelection(idx, { scrollIntoView: false });
    };
    searchUI.list.appendChild(li);
  }

  function focusSearchHitInPane(pane, filePath, from, to, tries = 10) {
    if (!pane || typeof filePath !== 'string' || !filePath) return;
    const attempt = () => {
      const tab = pane.getActiveTab ? pane.getActiveTab() : null;
      if (tab && tab.path === filePath && pane.live && pane.live.cmView && pane.live.cmApi) {
        const docLen = pane.live.cmView.state.doc.length;
        const start = Math.max(0, Math.min(docLen, Number(from) || 0));
        const end = Math.max(start, Math.min(docLen, Number(to) || start));
        pane.live.cmView.dispatch({ selection: { anchor: start, head: end }, scrollIntoView: true });
        pane.live.cmApi.focus();
        return;
      }
      if (tries <= 0) return;
      setTimeout(() => focusSearchHitInPane(pane, filePath, from, to, tries - 1), 70);
    };
    attempt();
  }

  async function openSearchResult(hit, query) {
    if (!hit || !hit.entry) return;
    const entry = hit.entry;
    closeSearchPanel({ clearInput: true });
    if (entry.type === 'app') {
      await openSearchAppEntry(entry);
      return;
    }
    if (entry.type === 'folder') {
      if (!activePane) createPane();
      const pane = activePane || panes[0] || null;
      if (pane) {
        await openStorageTabInPane(pane, {
          path: normalizeStoragePath(entry.path || ''),
          forceNew: true,
          reuseAnyPane: false
        });
      }
      if (entry.path) await revealPathInSidebar(entry.path);
      return;
    }
    if (!activePane) createPane();
    const pane = activePane;
    await pane.addTab(entry.path, entry.name);
    await revealPathInSidebar(entry.path);
    const terms = getSearchTerms(query);
    if (hit.firstContentIndex >= 0 && terms.length) {
      let focusTerm = terms[0];
      if (entry.contentLower) {
        const atMatchIndex = terms.find((term) => {
          const sample = entry.contentLower.slice(hit.firstContentIndex, hit.firstContentIndex + term.length);
          return sample === term;
        });
        if (atMatchIndex) focusTerm = atMatchIndex;
      }
      focusSearchHitInPane(pane, entry.path, hit.firstContentIndex, hit.firstContentIndex + focusTerm.length);
    }
  }

  function renderSearchResults(query) {
    if (!searchUI.list) return;
    if (!isSearchPanelOpen()) {
      searchUI.list.hidden = true;
      searchSelectionIndex = -1;
      return;
    }
    const q = String(query || '').trim();
    searchUI.list.classList.remove('is-loading');
    searchUI.list.innerHTML = '';
    searchSelectionIndex = -1;
    updateSearchClearButtonVisibility();
    if (!q) {
      searchUI.list.hidden = true;
      return;
    }
    searchUI.list.hidden = false;

    if (!searchIndexEntries.length && searchIndexPromise) {
      const li = document.createElement('li');
      li.style.color = 'var(--muted-strong, var(--text-sub))';
      li.textContent = 'Indexing notes...';
      searchUI.list.appendChild(li);
      return;
    }

    const terms = getSearchTerms(q);
    const quickCreateNoteName = getQuickCreateSearchNoteName(q);
    if (!terms.length && !quickCreateNoteName) {
      const li = document.createElement('li');
      li.style.color = 'var(--muted-strong, var(--text-sub))';
      li.textContent = q.startsWith('/')
        ? 'Type a note name after "/" to create it.'
        : 'No matches';
      searchUI.list.appendChild(li);
      return;
    }
    if (quickCreateNoteName) {
      const quickCreateEntry = createAppSearchEntry({
        name: `Create new note "${quickCreateNoteName}"`,
        path: 'Quick Create',
        content: 'Press Enter to pick a folder, or skip to save it in the root folder.',
        keywords: ['new note', 'quick create', quickCreateNoteName],
        action: 'quick-create-note',
        payload: { noteName: quickCreateNoteName },
        icon: SEARCH_APP_ICON
      });
      if (quickCreateEntry) {
        appendSearchResultListItem({
          entry: quickCreateEntry,
          score: Number.MAX_SAFE_INTEGER,
          firstContentIndex: -1
        }, q);
      }
    }
    const scored = [];
    searchIndexEntries.forEach((entry) => {
      const hit = scoreSearchEntry(entry, terms);
      if (hit) scored.push(hit);
    });
    scored.sort((a, b) => b.score - a.score || a.entry.name.localeCompare(b.entry.name));
    const matches = scored.slice(0, 80);

    matches.forEach((hit) => {
      appendSearchResultListItem(hit, q);
    });

    const renderedItems = getSearchResultItems();
    if (renderedItems.length > 0) {
      setSearchSelection(0, { scrollIntoView: false });
    }

    if (renderedItems.length === 0) {
      const li = document.createElement('li');
      li.style.color = 'var(--muted-strong, var(--text-sub))';
      li.textContent = 'No matches';
      searchUI.list.appendChild(li);
    }
  }

  async function openSearchPanel(options = {}) {
    if (!searchUI.popup || !searchUI.input) return;
    if (activeQuickCreateFolderPromptCloser) {
      try { activeQuickCreateFolderPromptCloser(); } catch (error) {}
    }
    closeAllPaneFindPanels();
    updateSearchOpenWidth();
    setCenteredPopupOpen(searchUI.popup, true);
    syncSearchLayerState(true);
    if (searchUI.btn) searchUI.btn.setAttribute('aria-expanded', 'true');
    if (options.focus !== false) searchUI.input.focus();
    if (options.select === true) searchUI.input.select();
    updateSearchClearButtonVisibility();
    if (searchUI.list) {
      searchUI.list.classList.remove('is-loading');
    }
    refreshSearchDynamicEntries();
    renderSearchResults(searchUI.input.value || '');
    const hasCachedIndex = searchIndexEntries.length > 0;
    const shouldRefresh = !hasCachedIndex || (Date.now() - searchIndexTimestamp) > SEARCH_INDEX_TTL;
    const buildPromise = ensureSearchIndex(shouldRefresh);
    buildPromise.then(() => {
      if (!isSearchPanelOpen()) return;
      refreshSearchDynamicEntries();
      renderSearchResults(searchUI.input ? (searchUI.input.value || '') : '');
    });
    if (!hasCachedIndex) {
      await buildPromise;
      refreshSearchDynamicEntries();
      renderSearchResults(searchUI.input ? (searchUI.input.value || '') : '');
    }
  }

  function closeSearchPanel(options = {}) {
    if (!searchUI.popup) return;
    setCenteredPopupOpen(searchUI.popup, false);
    syncSearchLayerState(false);
    if (searchUI.btn) searchUI.btn.setAttribute('aria-expanded', 'false');
    searchSelectionIndex = -1;
    if (options.clearInput && searchUI.input) {
      searchUI.input.value = '';
    }
    updateSearchClearButtonVisibility();
    if (searchUI.list) {
      searchUI.list.hidden = true;
      searchUI.list.innerHTML = '';
      searchUI.list.classList.remove('is-loading');
    }
    if (!options.keepFocus && searchUI.input && document.activeElement === searchUI.input) {
      searchUI.input.blur();
    }
  }

  const NOTE_FIND_ARROW_UP_ICON = `<svg class="note-find-arrow-icon" width="14" height="14" viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="M6.5 14.5 12 9l5.5 5.5" stroke="currentColor" stroke-width="2.35" stroke-linecap="round" stroke-linejoin="round"></path></svg>`;
  const NOTE_FIND_ARROW_DOWN_ICON = `<svg class="note-find-arrow-icon" width="14" height="14" viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="m6.5 9.5 5.5 5.5 5.5-5.5" stroke="currentColor" stroke-width="2.35" stroke-linecap="round" stroke-linejoin="round"></path></svg>`;
  const NOTE_FIND_TOGGLE_ICON = `<svg class="note-find-arrow-icon note-find-toggle-arrow" width="14" height="14" viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="m9 6.5 5.5 5.5L9 17.5" stroke="currentColor" stroke-width="2.35" stroke-linecap="round" stroke-linejoin="round"></path></svg>`;
  const NOTE_FIND_CASE_ICON = `<svg class="note-find-case-icon" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.15" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M4 17 7.1 7.2 10.2 17"/><path d="M5.2 13h3.8"/><circle cx="16.7" cy="13.7" r="2.5"/><path d="M19.2 13.7V17"/></svg>`;
  const NOTE_FIND_REPLACE_ICON = `<svg class="note-find-action-icon" width="15" height="15" viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="m5.3 12.6 3 3.1 7-7.2" stroke="currentColor" stroke-width="2.55" stroke-linecap="round" stroke-linejoin="round"></path></svg>`;
  const NOTE_FIND_REPLACE_ALL_ICON = `<svg class="note-find-action-icon note-find-action-icon-double" width="17" height="17" viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="m3.1 12.7 2.4 2.4 5.3-5.5" stroke="currentColor" stroke-width="2.35" stroke-linecap="round" stroke-linejoin="round"></path><path d="m8.2 12.7 2.4 2.4 5.3-5.5" stroke="currentColor" stroke-width="2.35" stroke-linecap="round" stroke-linejoin="round"></path></svg>`;

  function syncPaneFindQueryHighlight(pane, query, options = {}) {
    if (!pane || !pane.live || !pane.live.cmApi || typeof pane.live.cmApi.setSearchQuery !== 'function') return;
    pane.live.cmApi.setSearchQuery(String(query || ''), {
      caseSensitive: Boolean(options.caseSensitive)
    });
  }

  function clearPaneRenderedFindHighlights(pane) {
    const host = pane && pane.ui && pane.ui.liveEditor ? pane.ui.liveEditor : null;
    if (!host) return;
    const marks = host.querySelectorAll('mark.note-find-widget-highlight');
    marks.forEach((mark) => {
      if (!mark || !mark.parentNode) return;
      const textNode = document.createTextNode(mark.textContent || '');
      mark.parentNode.replaceChild(textNode, mark);
    });
  }

  function queuePaneRenderedFindHighlights(pane, query, options = {}) {
    if (!pane || !pane.findState) return;
    if (pane.findState.renderHighlightRaf) {
      cancelAnimationFrame(pane.findState.renderHighlightRaf);
      pane.findState.renderHighlightRaf = null;
    }
    const needle = String(query || '');
    if (!needle) {
      clearPaneRenderedFindHighlights(pane);
      return;
    }
    pane.findState.renderHighlightRaf = requestAnimationFrame(() => {
      pane.findState.renderHighlightRaf = requestAnimationFrame(() => {
        pane.findState.renderHighlightRaf = null;
        applyPaneRenderedFindHighlights(pane, needle, options);
      });
    });
  }

  function applyPaneRenderedFindHighlights(pane, query, options = {}) {
    try {
      clearPaneRenderedFindHighlights(pane);
      const host = pane && pane.ui && pane.ui.liveEditor ? pane.ui.liveEditor : null;
      const needle = String(query || '');
      if (!host || !needle) return;
      const caseSensitive = Boolean(options.caseSensitive);
      const highlightRegex = new RegExp(escapeRegExp(needle), caseSensitive ? 'g' : 'gi');
      const NF = (typeof window !== 'undefined' && window.NodeFilter)
        ? window.NodeFilter
        : { SHOW_TEXT: 4, FILTER_ACCEPT: 1, FILTER_REJECT: 2 };
      const blockNodes = host.querySelectorAll('.cm-block-render');
      let highlightedCount = 0;
      blockNodes.forEach((block) => {
        const walker = document.createTreeWalker(
          block,
          NF.SHOW_TEXT,
          {
            acceptNode(node) {
              if (!node || !node.nodeValue || !node.nodeValue.trim()) return NF.FILTER_REJECT;
              const parent = node.parentElement;
              if (!parent) return NF.FILTER_REJECT;
              if (parent.closest('script,style,mark.note-find-widget-highlight')) return NF.FILTER_REJECT;
              return NF.FILTER_ACCEPT;
            }
          }
        );
        const targets = [];
        let textNode = walker.nextNode();
        while (textNode) {
          targets.push(textNode);
          textNode = walker.nextNode();
        }
        targets.forEach((node) => {
          if (highlightedCount >= 6000) return;
          const rawText = node.nodeValue || '';
          highlightRegex.lastIndex = 0;
          const matches = [];
          let match;
          while ((match = highlightRegex.exec(rawText)) !== null) {
            matches.push({ index: match.index, value: match[0] });
            if (match[0].length === 0) highlightRegex.lastIndex += 1;
            if (matches.length >= 120) break;
            if (highlightedCount + matches.length >= 6000) break;
          }
          if (!matches.length) return;
          const fragment = document.createDocumentFragment();
          let cursor = 0;
          matches.forEach((hit) => {
            const start = hit.index;
            const end = start + hit.value.length;
            if (start > cursor) fragment.appendChild(document.createTextNode(rawText.slice(cursor, start)));
            const mark = document.createElement('mark');
            mark.className = 'note-find-widget-highlight';
            mark.textContent = rawText.slice(start, end);
            fragment.appendChild(mark);
            cursor = end;
            highlightedCount += 1;
          });
          if (cursor < rawText.length) fragment.appendChild(document.createTextNode(rawText.slice(cursor)));
          if (node.parentNode) node.parentNode.replaceChild(fragment, node);
        });
      });
    } catch (e) {}
  }

  function syncPaneFindCaseButton(pane) {
    if (!pane || !pane.ui || !pane.ui.findCaseBtn || !pane.findState) return;
    const isCaseSensitive = Boolean(pane.findState.matchCase);
    pane.ui.findCaseBtn.classList.toggle('is-active', isCaseSensitive);
    pane.ui.findCaseBtn.setAttribute('aria-pressed', isCaseSensitive ? 'true' : 'false');
    pane.ui.findCaseBtn.title = isCaseSensitive ? 'Match case: on' : 'Match case: off';
  }

  function ensurePaneFindViewportEl(pane) {
    if (!pane || !pane.ui || !pane.ui.findMarkers) return null;
    let viewport = pane.ui.findViewport;
    if (!viewport || !viewport.isConnected) {
      viewport = document.createElement('div');
      viewport.className = 'note-find-viewport';
      pane.ui.findMarkers.appendChild(viewport);
      pane.ui.findViewport = viewport;
    }
    return viewport;
  }

  function clearPaneFindMarkers(pane) {
    if (!pane || !pane.ui || !pane.ui.findMarkers) return;
    pane.ui.findMarkers.querySelectorAll('.note-find-marker').forEach((marker) => marker.remove());
  }

  function updatePaneFindViewportIndicator(pane) {
    if (!pane || !pane.ui || !pane.ui.findMarkers || !pane.findState || !pane.findState.open) return;
    const viewport = ensurePaneFindViewportEl(pane);
    if (!viewport) return;
    const scrollDom = pane.live && pane.live.cmView && pane.live.cmView.scrollDOM ? pane.live.cmView.scrollDOM : null;
    if (!scrollDom) {
      viewport.hidden = true;
      return;
    }
    const scrollHeight = Number(scrollDom.scrollHeight) || 0;
    const clientHeight = Number(scrollDom.clientHeight) || 0;
    if (scrollHeight <= 0 || clientHeight <= 0) {
      viewport.hidden = true;
      return;
    }
    const rawHeightPct = (clientHeight / scrollHeight) * 100;
    const heightPct = Math.max(8, Math.min(100, rawHeightPct));
    const maxTopPct = Math.max(0, 100 - heightPct);
    const scrollRange = Math.max(1, scrollHeight - clientHeight);
    const topPct = Math.max(0, Math.min(maxTopPct, (scrollDom.scrollTop / scrollRange) * maxTopPct));
    viewport.style.top = `${topPct}%`;
    viewport.style.height = `${heightPct}%`;
    viewport.hidden = false;
  }

  function setPaneFindReplaceExpanded(pane, expanded, options = {}) {
    if (!pane || !pane.ui || !pane.findState) return;
    const isExpanded = Boolean(expanded);
    pane.findState.replaceExpanded = isExpanded;
    if (pane.ui.findReplaceRow) pane.ui.findReplaceRow.hidden = !isExpanded;
    if (pane.ui.findPanel) pane.ui.findPanel.classList.toggle('replace-open', isExpanded);
    if (pane.ui.findToggleReplaceBtn) {
      pane.ui.findToggleReplaceBtn.setAttribute('aria-expanded', isExpanded ? 'true' : 'false');
      pane.ui.findToggleReplaceBtn.classList.toggle('expanded', isExpanded);
      pane.ui.findToggleReplaceBtn.title = isExpanded ? 'Hide replace' : 'Show replace';
    }
    if (isExpanded && options.focusReplace && pane.ui.findReplaceInput) {
      pane.ui.findReplaceInput.focus();
      pane.ui.findReplaceInput.select();
    }
  }

  function ensurePaneFindUi(pane) {
    if (!pane || !pane.ui || pane.ui.findPanel) return;
    const paneBody = pane.el && pane.el.querySelector ? pane.el.querySelector('.pane-body') : null;
    if (!paneBody) return;
    const panel = document.createElement('div');
    panel.className = 'note-find-panel';
    panel.hidden = true;
    panel.innerHTML = `
      <div class="note-find-grid">
        <button type="button" class="note-find-btn icon-btn note-find-toggle-replace" title="Show replace" aria-expanded="false" aria-label="Toggle replace row">${NOTE_FIND_TOGGLE_ICON}</button>
        <div class="note-find-row note-find-main-row">
          <input class="note-find-input" type="text" placeholder="Find in note">
          <span class="note-find-meta">0/0</span>
          <button type="button" class="note-find-btn note-find-case" title="Match case: off" aria-pressed="false" aria-label="Toggle match case">Aa</button>
          <button type="button" class="note-find-btn icon-btn note-find-prev" title="Previous match" aria-label="Previous match">${NOTE_FIND_ARROW_UP_ICON}</button>
          <button type="button" class="note-find-btn icon-btn note-find-next" title="Next match" aria-label="Next match">${NOTE_FIND_ARROW_DOWN_ICON}</button>
          <button type="button" class="note-find-btn close-btn" title="Close" aria-label="Close find">${ICONS.CLOSE_X}</button>
        </div>
        <div class="note-find-row note-find-replace-row" hidden>
          <input class="note-replace-input" type="text" placeholder="Replace with">
          <button type="button" class="note-find-btn note-find-replace" title="Replace match" aria-label="Replace match">${NOTE_FIND_REPLACE_ICON}</button>
          <button type="button" class="note-find-btn note-find-replace-all" title="Replace all matches" aria-label="Replace all matches">${NOTE_FIND_REPLACE_ALL_ICON}</button>
        </div>
      </div>
    `;
    const markers = document.createElement('div');
    markers.className = 'note-find-markers';
    markers.hidden = true;
    const viewport = document.createElement('div');
    viewport.className = 'note-find-viewport';
    viewport.hidden = true;
    markers.appendChild(viewport);
    paneBody.append(panel, markers);

    pane.ui.findPanel = panel;
    pane.ui.findMarkers = markers;
    pane.ui.findViewport = viewport;
    pane.ui.findInput = panel.querySelector('.note-find-input');
    pane.ui.findMeta = panel.querySelector('.note-find-meta');
    pane.ui.findPrevBtn = panel.querySelector('.note-find-prev');
    pane.ui.findNextBtn = panel.querySelector('.note-find-next');
    pane.ui.findCaseBtn = panel.querySelector('.note-find-case');
    pane.ui.findCloseBtn = panel.querySelector('.close-btn');
    pane.ui.findToggleReplaceBtn = panel.querySelector('.note-find-toggle-replace');
    pane.ui.findReplaceRow = panel.querySelector('.note-find-replace-row');
    pane.ui.findReplaceInput = panel.querySelector('.note-replace-input');
    pane.ui.findReplaceBtn = panel.querySelector('.note-find-replace');
    pane.ui.findReplaceAllBtn = panel.querySelector('.note-find-replace-all');

    pane.findState = pane.findState || {
      open: false,
      query: '',
      replace: '',
      matches: [],
      activeIndex: -1,
      matchCase: false,
      replaceExpanded: false,
      builtInReplaceOpen: false,
      renderHighlightRaf: null,
      refreshTimer: null
    };
    if (typeof pane.findState.matchCase !== 'boolean') pane.findState.matchCase = false;
    if (typeof pane.findState.replaceExpanded !== 'boolean') pane.findState.replaceExpanded = false;
    if (typeof pane.findState.builtInReplaceOpen !== 'boolean') pane.findState.builtInReplaceOpen = false;
    if (!Number.isFinite(pane.findState.renderHighlightRaf)) pane.findState.renderHighlightRaf = null;

    panel.addEventListener('mousedown', (evt) => evt.stopPropagation());
    panel.addEventListener('click', (evt) => evt.stopPropagation());

    if (pane.ui.findInput) {
      pane.ui.findInput.addEventListener('input', () => refreshPaneFind(pane, { resetIndex: true, focusEditor: false, preferSelection: true }));
      pane.ui.findInput.addEventListener('keydown', (evt) => {
        if (evt.key === 'Enter') {
          evt.preventDefault();
          stepPaneFindMatch(pane, evt.shiftKey ? -1 : 1);
        }
        if (evt.key === 'Escape') {
          evt.preventDefault();
          closePaneFindPanel(pane);
        }
      });
    }
    if (pane.ui.findReplaceInput) {
      pane.ui.findReplaceInput.addEventListener('keydown', (evt) => {
        if (evt.key === 'Enter') {
          evt.preventDefault();
          replaceCurrentPaneMatch(pane);
        }
        if (evt.key === 'Escape') {
          evt.preventDefault();
          setPaneFindReplaceExpanded(pane, false);
          if (pane.ui.findInput) pane.ui.findInput.focus();
        }
      });
    }
    if (pane.ui.findPrevBtn) pane.ui.findPrevBtn.onclick = () => stepPaneFindMatch(pane, -1);
    if (pane.ui.findNextBtn) pane.ui.findNextBtn.onclick = () => stepPaneFindMatch(pane, 1);
    if (pane.ui.findCaseBtn) {
      pane.ui.findCaseBtn.onclick = () => {
        pane.findState.matchCase = !Boolean(pane.findState.matchCase);
        syncPaneFindCaseButton(pane);
        refreshPaneFind(pane, { resetIndex: true, focusEditor: false, preferSelection: true });
      };
    }
    if (pane.ui.findCloseBtn) pane.ui.findCloseBtn.onclick = () => closePaneFindPanel(pane);
    if (pane.ui.findToggleReplaceBtn) {
      pane.ui.findToggleReplaceBtn.onclick = () => {
        setPaneFindReplaceExpanded(pane, !pane.findState.replaceExpanded, { focusReplace: !pane.findState.replaceExpanded });
      };
    }
    if (pane.ui.findReplaceBtn) pane.ui.findReplaceBtn.onclick = () => replaceCurrentPaneMatch(pane);
    if (pane.ui.findReplaceAllBtn) pane.ui.findReplaceAllBtn.onclick = () => replaceAllPaneMatches(pane);
    if (pane.ui.findMarkers) {
      pane.ui.findMarkers.addEventListener('click', (evt) => {
        const target = evt.target && evt.target.closest ? evt.target.closest('.note-find-marker') : null;
        if (!target) return;
        const index = Number(target.dataset.matchIndex);
        if (!Number.isFinite(index)) return;
        selectPaneFindMatch(pane, index, { focusEditor: true });
      });
    }
    syncPaneFindCaseButton(pane);
    setPaneFindReplaceExpanded(pane, Boolean(pane.findState.replaceExpanded));
  }

  function closePaneFindPanel(pane) {
    if (!pane || !pane.ui || !pane.ui.findPanel || !pane.findState) return;
    pane.findState.open = false;
    if (pane.findState.renderHighlightRaf) {
      cancelAnimationFrame(pane.findState.renderHighlightRaf);
      pane.findState.renderHighlightRaf = null;
    }
    pane.ui.findPanel.hidden = true;
    syncPaneFindQueryHighlight(pane, '', { caseSensitive: Boolean(pane.findState.matchCase) });
    clearPaneRenderedFindHighlights(pane);
    if (pane.ui.findMarkers) {
      pane.ui.findMarkers.hidden = true;
      clearPaneFindMarkers(pane);
    }
    if (pane.ui.findViewport) {
      pane.ui.findViewport.hidden = true;
    }
  }

  function closeAllPaneFindPanels(exceptPane = null) {
    panes.forEach((pane) => {
      if (!pane || pane === exceptPane) return;
      closePaneFindPanel(pane);
      closePaneBuiltInFindPanel(pane);
    });
  }

  function getPaneBuiltInSearchPanel(pane) {
    if (!pane || !pane.ui || !pane.ui.liveEditor || !pane.ui.liveEditor.querySelector) return null;
    return pane.ui.liveEditor.querySelector('.cm-panels .cm-search');
  }

  function closePaneBuiltInFindPanel(pane) {
    if (!pane || !pane.live || !pane.findState) return;
    if (pane.live.cmApi && typeof pane.live.cmApi.closeSearchPanel === 'function') {
      try { pane.live.cmApi.closeSearchPanel(); } catch (e) {}
    }
    pane.findState.open = false;
    pane.findState.query = '';
    pane.findState.matches = [];
    pane.findState.activeIndex = -1;
    clearPaneRenderedFindHighlights(pane);
    if (pane.ui && pane.ui.findMarkers) {
      pane.ui.findMarkers.hidden = true;
      clearPaneFindMarkers(pane);
    }
    if (pane.ui && pane.ui.findViewport) pane.ui.findViewport.hidden = true;
  }

  function syncBuiltInReplaceToggleState(pane, panel) {
    if (!pane || !panel || !pane.findState) return;
    const isOpen = Boolean(pane.findState.builtInReplaceOpen);
    panel.classList.toggle('noto-replace-open', isOpen);
    const toggleBtn = panel.querySelector('.noto-replace-toggle');
    if (toggleBtn) {
      toggleBtn.classList.toggle('expanded', isOpen);
      toggleBtn.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
      toggleBtn.title = isOpen ? 'Hide replace' : 'Show replace';
    }
  }

  function syncBuiltInCaseButtonState(panel, caseInput) {
    if (!panel) return;
    const caseBtn = panel.querySelector('.noto-case-toggle');
    if (!caseBtn) return;
    const active = Boolean(caseInput && caseInput.checked);
    caseBtn.classList.toggle('is-active', active);
    caseBtn.setAttribute('aria-pressed', active ? 'true' : 'false');
    caseBtn.title = active ? 'Match case: on' : 'Match case: off';
  }

  function enhanceBuiltInFindPanel(pane, panel) {
    if (!pane || !panel) return;
    if (!pane.findState) return;
    panel.classList.add('noto-enhanced');

    const nextBtn = panel.querySelector('button[name="next"]');
    const prevBtn = panel.querySelector('button[name="prev"]');
    const selectBtn = panel.querySelector('button[name="select"]');
    const closeBtn = panel.querySelector('button[name="close"]');
    const replaceBtn = panel.querySelector('button[name="replace"]');
    const replaceAllBtn = panel.querySelector('button[name="replaceAll"]');
    const searchInput = panel.querySelector('input[name="search"]');
    const replaceInput = panel.querySelector('input[name="replace"]');
    const caseInput = panel.querySelector('input[name="case"]');
    const caseLabel = caseInput && caseInput.closest ? caseInput.closest('label') : null;
    const reInput = panel.querySelector('input[name="re"]');
    const reLabel = reInput && reInput.closest ? reInput.closest('label') : null;
    const wordInput = panel.querySelector('input[name="word"]');
    const wordLabel = wordInput && wordInput.closest ? wordInput.closest('label') : null;

    if (nextBtn && !nextBtn.dataset.notoIconized) {
      nextBtn.innerHTML = NOTE_FIND_ARROW_DOWN_ICON;
      nextBtn.dataset.notoIconized = '1';
      nextBtn.setAttribute('aria-label', 'Next match');
      nextBtn.title = 'Next match';
    }
    if (prevBtn && !prevBtn.dataset.notoIconized) {
      prevBtn.innerHTML = NOTE_FIND_ARROW_UP_ICON;
      prevBtn.dataset.notoIconized = '1';
      prevBtn.setAttribute('aria-label', 'Previous match');
      prevBtn.title = 'Previous match';
    }
    if (closeBtn && !closeBtn.dataset.notoIconized) {
      closeBtn.innerHTML = ICONS.CLOSE_X;
      closeBtn.dataset.notoIconized = '1';
      closeBtn.setAttribute('aria-label', 'Close find');
      closeBtn.title = 'Close';
    }
    if (replaceBtn && !replaceBtn.dataset.notoIconized) {
      replaceBtn.innerHTML = NOTE_FIND_REPLACE_ICON;
      replaceBtn.dataset.notoIconized = '1';
      replaceBtn.setAttribute('aria-label', 'Replace match');
      replaceBtn.title = 'Replace match';
    }
    if (replaceAllBtn && !replaceAllBtn.dataset.notoIconized) {
      replaceAllBtn.innerHTML = NOTE_FIND_REPLACE_ALL_ICON;
      replaceAllBtn.dataset.notoIconized = '1';
      replaceAllBtn.setAttribute('aria-label', 'Replace all matches');
      replaceAllBtn.title = 'Replace all matches';
    }
    if (closeBtn && !closeBtn.dataset.notoBoundClose) {
      closeBtn.addEventListener('click', () => closePaneBuiltInFindPanel(pane));
      closeBtn.dataset.notoBoundClose = '1';
    }

    if (selectBtn) selectBtn.classList.add('noto-hidden-control');
    if (caseLabel) caseLabel.classList.add('noto-hidden-control');
    if (reLabel) reLabel.classList.add('noto-hidden-control');
    if (wordLabel) wordLabel.classList.add('noto-hidden-control');

    panel.querySelectorAll('label').forEach((label) => label.classList.add('noto-hidden-control'));
    const allowedButtons = new Set(['prev', 'next', 'replace', 'replaceAll', 'close']);
    panel.querySelectorAll('button').forEach((btn) => {
      if (!btn || btn.classList.contains('noto-case-toggle') || btn.classList.contains('noto-replace-toggle')) return;
      const name = String(btn.getAttribute('name') || '');
      if (!allowedButtons.has(name)) btn.classList.add('noto-hidden-control');
    });

    if (!panel.querySelector('.noto-case-toggle')) {
      const caseBtn = document.createElement('button');
      caseBtn.type = 'button';
      caseBtn.className = 'cm-button noto-case-toggle';
      caseBtn.innerHTML = NOTE_FIND_CASE_ICON;
      caseBtn.setAttribute('aria-pressed', 'false');
      caseBtn.setAttribute('aria-label', 'Toggle match case');
      caseBtn.title = 'Match case: off';
      caseBtn.addEventListener('click', () => {
        if (!caseInput) return;
        caseInput.checked = !caseInput.checked;
        caseInput.dispatchEvent(new Event('change', { bubbles: true }));
        caseInput.dispatchEvent(new Event('keyup', { bubbles: true }));
        syncBuiltInCaseButtonState(panel, caseInput);
        schedulePaneBuiltInFindRefresh(pane);
      });
      if (nextBtn && nextBtn.parentNode === panel) panel.insertBefore(caseBtn, nextBtn);
      else panel.appendChild(caseBtn);
    }

    if (!panel.querySelector('.noto-replace-toggle')) {
      const replaceToggle = document.createElement('button');
      replaceToggle.type = 'button';
      replaceToggle.className = 'cm-button noto-replace-toggle';
      replaceToggle.innerHTML = NOTE_FIND_TOGGLE_ICON;
      replaceToggle.setAttribute('aria-expanded', 'false');
      replaceToggle.setAttribute('aria-label', 'Toggle replace row');
      replaceToggle.title = 'Show replace';
      replaceToggle.addEventListener('click', () => {
        pane.findState.builtInReplaceOpen = !Boolean(pane.findState.builtInReplaceOpen);
        syncBuiltInReplaceToggleState(pane, panel);
        if (pane.findState.builtInReplaceOpen && replaceInput) {
          replaceInput.focus();
          replaceInput.select();
        } else if (searchInput) {
          searchInput.focus();
        }
      });
      if (searchInput && searchInput.parentNode === panel) panel.insertBefore(replaceToggle, searchInput);
      else panel.insertBefore(replaceToggle, panel.firstChild);
    }

    syncBuiltInCaseButtonState(panel, caseInput);
    syncBuiltInReplaceToggleState(pane, panel);
  }

  function refreshPaneFindFromBuiltInPanel(pane) {
    if (!pane || !pane.live || !pane.live.cmApi) return;
    ensurePaneFindUi(pane);
    if (pane.ui && pane.ui.findPanel) pane.ui.findPanel.hidden = true;
    if (!pane.findState) return;
    const searchPanel = getPaneBuiltInSearchPanel(pane);
    if (searchPanel) enhanceBuiltInFindPanel(pane, searchPanel);
    const searchInput = searchPanel && searchPanel.querySelector ? searchPanel.querySelector('input[name="search"]') : null;
    const caseInput = searchPanel && searchPanel.querySelector ? searchPanel.querySelector('input[name="case"]') : null;
    const query = String(searchInput && typeof searchInput.value === 'string' ? searchInput.value : '').trim();
    const caseSensitive = Boolean(caseInput && caseInput.checked);
    if (!searchPanel || !query) {
      pane.findState.open = false;
      pane.findState.query = '';
      pane.findState.matches = [];
      pane.findState.activeIndex = -1;
      clearPaneRenderedFindHighlights(pane);
      if (pane.ui.findMarkers) {
        pane.ui.findMarkers.hidden = true;
        clearPaneFindMarkers(pane);
      }
      if (pane.ui.findViewport) pane.ui.findViewport.hidden = true;
      return;
    }
    pane.findState.open = true;
    pane.findState.query = query;
    pane.findState.matchCase = caseSensitive;
    queuePaneRenderedFindHighlights(pane, query, { caseSensitive });
    const text = getPaneFindDocText(pane);
    const matches = computeTextMatches(text, query, { caseSensitive });
    pane.findState.matches = matches;
    const selection = pane.live.cmApi.getSelection ? pane.live.cmApi.getSelection() : null;
    let activeIndex = -1;
    if (matches.length) {
      if (selection && Number.isFinite(selection.from) && Number.isFinite(selection.to) && selection.to > selection.from) {
        activeIndex = matches.findIndex((m) => m.from === selection.from && m.to === selection.to);
      }
      if (activeIndex < 0 && selection && Number.isFinite(selection.from)) {
        activeIndex = matches.findIndex((m) => m.from <= selection.from && m.to >= selection.from);
      }
      if (activeIndex < 0) activeIndex = 0;
    }
    pane.findState.activeIndex = activeIndex;
    renderPaneFindMarkers(pane, text);
  }

  function schedulePaneBuiltInFindRefresh(pane) {
    if (!pane) return;
    if (!pane.findState) pane.findState = { open: false, query: '', replace: '', matches: [], activeIndex: -1, matchCase: false, replaceExpanded: false, builtInReplaceOpen: false, renderHighlightRaf: null, refreshTimer: null };
    if (typeof pane.findState.builtInReplaceOpen !== 'boolean') pane.findState.builtInReplaceOpen = false;
    if (pane.findState.refreshTimer) clearTimeout(pane.findState.refreshTimer);
    pane.findState.refreshTimer = setTimeout(() => {
      pane.findState.refreshTimer = null;
      refreshPaneFindFromBuiltInPanel(pane);
    }, 40);
  }

  function getPaneFindDocText(pane) {
    if (!pane) return '';
    if (pane.live && pane.live.cmApi && typeof pane.live.cmApi.getDoc === 'function') {
      return pane.live.cmApi.getDoc();
    }
    return pane.getCurrentEditorText ? pane.getCurrentEditorText() : '';
  }

  function computeTextMatches(text, query, options = {}) {
    const source = String(text || '');
    const needle = String(query || '').trim();
    if (!needle) return [];
    const caseSensitive = Boolean(options.caseSensitive);
    const sourceScan = caseSensitive ? source : source.toLowerCase();
    const needleScan = caseSensitive ? needle : needle.toLowerCase();
    const out = [];
    let cursor = 0;
    while (cursor <= sourceScan.length - needleScan.length) {
      const idx = sourceScan.indexOf(needleScan, cursor);
      if (idx === -1) break;
      out.push({ from: idx, to: idx + needle.length });
      cursor = idx + Math.max(1, needle.length);
      if (out.length >= 5000) break;
    }
    return out;
  }

  function renderPaneFindMarkers(pane, docText = '') {
    if (!pane || !pane.ui || !pane.ui.findMarkers || !pane.findState || !pane.findState.open) return;
    const markersEl = pane.ui.findMarkers;
    const hasQuery = Boolean(String(pane.findState.query || '').trim());
    const matches = Array.isArray(pane.findState.matches) ? pane.findState.matches : [];
    clearPaneFindMarkers(pane);
    if (!matches.length) {
      markersEl.hidden = !hasQuery;
      if (pane.ui.findViewport) pane.ui.findViewport.hidden = !hasQuery;
      if (hasQuery) updatePaneFindViewportIndicator(pane);
      return;
    }

    const doc = pane.live && pane.live.cmView ? pane.live.cmView.state.doc : null;
    const totalLines = doc ? doc.lines : Math.max(1, String(docText || '').split('\n').length);
    const lineAt = (pos) => {
      if (doc) {
        const safePos = Math.max(0, Math.min(doc.length, Number(pos) || 0));
        return doc.lineAt(safePos).number;
      }
      let line = 1;
      for (let i = 0; i < pos && i < docText.length; i += 1) {
        if (docText.charCodeAt(i) === 10) line += 1;
      }
      return line;
    };

    const sampledIndices = [];
    if (matches.length <= NOTE_FIND_MAX_MARKERS) {
      for (let i = 0; i < matches.length; i += 1) sampledIndices.push(i);
    } else {
      const step = (matches.length - 1) / Math.max(1, NOTE_FIND_MAX_MARKERS - 1);
      const seen = new Set();
      for (let i = 0; i < NOTE_FIND_MAX_MARKERS; i += 1) {
        const idx = Math.round(i * step);
        if (seen.has(idx)) continue;
        seen.add(idx);
        sampledIndices.push(idx);
      }
    }

    sampledIndices.forEach((matchIndex) => {
      const match = matches[matchIndex];
      if (!match) return;
      const marker = document.createElement('div');
      marker.className = 'note-find-marker';
      marker.dataset.matchIndex = String(matchIndex);
      if (matchIndex === pane.findState.activeIndex) marker.classList.add('current');
      const lineNo = lineAt(match.from);
      const topRatio = totalLines <= 1 ? 0 : (lineNo - 1) / (totalLines - 1);
      marker.style.top = `${Math.max(0, Math.min(100, topRatio * 100))}%`;
      markersEl.appendChild(marker);
    });
    markersEl.hidden = false;
    updatePaneFindViewportIndicator(pane);
  }

  function syncPaneFindMeta(pane) {
    if (!pane || !pane.ui || !pane.findState || !pane.ui.findMeta) return;
    const state = pane.findState;
    const total = Array.isArray(state.matches) ? state.matches.length : 0;
    const hasQuery = Boolean(String(state.query || '').trim());
    const current = total > 0 && state.activeIndex >= 0 ? state.activeIndex + 1 : 0;
    pane.ui.findMeta.textContent = hasQuery ? `${current}/${total}` : '0/0';
    if (pane.ui.findPrevBtn) pane.ui.findPrevBtn.disabled = total <= 1;
    if (pane.ui.findNextBtn) pane.ui.findNextBtn.disabled = total <= 1;
    if (pane.ui.findReplaceBtn) pane.ui.findReplaceBtn.disabled = total === 0;
    if (pane.ui.findReplaceAllBtn) pane.ui.findReplaceAllBtn.disabled = total === 0;
  }

  function selectPaneFindMatch(pane, targetIndex, options = {}) {
    if (!pane || !pane.findState || !Array.isArray(pane.findState.matches)) return;
    const total = pane.findState.matches.length;
    if (!total) {
      pane.findState.activeIndex = -1;
      syncPaneFindMeta(pane);
      renderPaneFindMarkers(pane, getPaneFindDocText(pane));
      return;
    }
    const wrapped = ((Number(targetIndex) || 0) % total + total) % total;
    pane.findState.activeIndex = wrapped;
    const match = pane.findState.matches[wrapped];
    if (match && pane.live && pane.live.cmView) {
      const docLen = pane.live.cmView.state.doc.length;
      const from = Math.max(0, Math.min(docLen, match.from));
      const to = Math.max(from, Math.min(docLen, match.to));
      pane.live.cmView.dispatch({
        selection: { anchor: from, head: to },
        scrollIntoView: true
      });
      if (options.focusEditor !== false && pane.live.cmApi) pane.live.cmApi.focus();
    } else if (match && pane.live && pane.live.cmApi) {
      pane.live.cmApi.setSelection(match.from, match.to);
      if (options.focusEditor !== false) pane.live.cmApi.focus();
    }
    syncPaneFindMeta(pane);
    renderPaneFindMarkers(pane, getPaneFindDocText(pane));
  }

  function stepPaneFindMatch(pane, delta) {
    if (!pane || !pane.findState) return;
    const total = pane.findState.matches.length;
    if (!total) return;
    const base = pane.findState.activeIndex >= 0 ? pane.findState.activeIndex : 0;
    selectPaneFindMatch(pane, base + (Number(delta) || 1), { focusEditor: true });
  }

  function refreshPaneFind(pane, options = {}) {
    if (!pane || !pane.findState || !pane.ui || !pane.ui.findInput) return;
    if (!pane.findState.open) return;
    const query = String(pane.ui.findInput.value || '').trim();
    const caseSensitive = Boolean(pane.findState.matchCase);
    pane.findState.query = query;
    syncPaneFindQueryHighlight(pane, query, { caseSensitive });
    queuePaneRenderedFindHighlights(pane, query, { caseSensitive });
    pane.findState.replace = pane.ui.findReplaceInput ? String(pane.ui.findReplaceInput.value || '') : '';
    const tab = pane.getActiveTab ? pane.getActiveTab() : null;
    if (!tab || !query) {
      pane.findState.matches = [];
      pane.findState.activeIndex = -1;
      syncPaneFindMeta(pane);
      if (pane.ui.findMarkers) {
        pane.ui.findMarkers.hidden = true;
        clearPaneFindMarkers(pane);
      }
      if (pane.ui.findViewport) {
        pane.ui.findViewport.hidden = true;
      }
      return;
    }

    const text = getPaneFindDocText(pane);
    const previousMatches = Array.isArray(pane.findState.matches) ? pane.findState.matches : [];
    const previousActiveMatch = previousMatches[pane.findState.activeIndex] || null;
    const matches = computeTextMatches(text, query, { caseSensitive });
    pane.findState.matches = matches;

    let nextIndex = -1;
    if (matches.length > 0) {
      if (options.resetIndex) {
        if (options.preferSelection && pane.live && pane.live.cmApi) {
          const selection = pane.live.cmApi.getSelection();
          const candidate = matches.findIndex((m) => m.to > selection.from);
          nextIndex = candidate >= 0 ? candidate : 0;
        } else {
          nextIndex = 0;
        }
      } else if (previousActiveMatch && Number.isFinite(previousActiveMatch.from)) {
        const candidate = matches.findIndex((m) => m.from >= previousActiveMatch.from);
        nextIndex = candidate >= 0 ? candidate : (matches.length - 1);
      } else {
        nextIndex = 0;
      }
    }
    pane.findState.activeIndex = nextIndex;
    syncPaneFindMeta(pane);
    renderPaneFindMarkers(pane, text);
    if (nextIndex >= 0 && options.select !== false) {
      selectPaneFindMatch(pane, nextIndex, { focusEditor: options.focusEditor !== false });
    }
  }

  function schedulePaneFindRefresh(pane) {
    if (!pane || !pane.findState) return;
    const hasVisibleCustomPanel = Boolean(pane.ui && pane.ui.findPanel && !pane.ui.findPanel.hidden);
    if (!hasVisibleCustomPanel) {
      schedulePaneBuiltInFindRefresh(pane);
      return;
    }
    if (!pane.findState.open) return;
    if (pane.findState.refreshTimer) clearTimeout(pane.findState.refreshTimer);
    pane.findState.refreshTimer = setTimeout(() => {
      pane.findState.refreshTimer = null;
      refreshPaneFind(pane, { resetIndex: false, select: false, focusEditor: false });
    }, 90);
  }

  function replaceCurrentPaneMatch(pane) {
    if (!pane || !pane.findState || !pane.findState.open) return;
    const matches = pane.findState.matches || [];
    const activeIdx = pane.findState.activeIndex;
    const match = matches[activeIdx];
    const tab = pane.getActiveTab ? pane.getActiveTab() : null;
    if (!match || !tab) return;
    const replacement = pane.ui && pane.ui.findReplaceInput ? String(pane.ui.findReplaceInput.value || '') : '';
    const text = getPaneFindDocText(pane);
    const nextText = `${text.slice(0, match.from)}${replacement}${text.slice(match.to)}`;
    const nextCaret = match.from + replacement.length;
    pane.commitLiveEditorText(nextText, nextCaret, {
      tabId: tab.id,
      tabPath: tab.path,
      focus: true,
      preserveScroll: true,
      anchorCaret: true
    });
    refreshPaneFind(pane, { resetIndex: false, focusEditor: true });
  }

  function replaceAllPaneMatches(pane) {
    if (!pane || !pane.findState || !pane.findState.open) return;
    const matches = pane.findState.matches || [];
    if (!matches.length) return;
    const tab = pane.getActiveTab ? pane.getActiveTab() : null;
    if (!tab) return;
    const replacement = pane.ui && pane.ui.findReplaceInput ? String(pane.ui.findReplaceInput.value || '') : '';
    let text = getPaneFindDocText(pane);
    for (let i = matches.length - 1; i >= 0; i -= 1) {
      const match = matches[i];
      text = `${text.slice(0, match.from)}${replacement}${text.slice(match.to)}`;
    }
    const anchor = pane.findState.activeIndex >= 0 ? matches[pane.findState.activeIndex].from + replacement.length : 0;
    pane.commitLiveEditorText(text, anchor, {
      tabId: tab.id,
      tabPath: tab.path,
      focus: true,
      preserveScroll: true,
      anchorCaret: true
    });
    showToast(`Replaced ${matches.length} match${matches.length === 1 ? '' : 'es'}.`, 'success');
    refreshPaneFind(pane, { resetIndex: true, focusEditor: true });
  }

  function openPaneFindPanel(pane) {
    if (!pane || !pane.getActiveTab || !pane.getActiveTab()) return;
    closeSearchPanel();
    ensurePaneFindUi(pane);
    closeAllPaneFindPanels(pane);
    pane.findState.open = true;
    pane.ui.findPanel.hidden = false;
    syncPaneFindCaseButton(pane);
    setPaneFindReplaceExpanded(pane, Boolean(pane.findState.replaceExpanded));

    const selectedText = (() => {
      if (!pane.live || !pane.live.cmApi) return '';
      const sel = pane.live.cmApi.getSelection();
      if (!sel || sel.empty) return '';
      const doc = pane.live.cmApi.getDoc();
      return doc.slice(sel.from, sel.to).trim();
    })();

    if (selectedText) pane.ui.findInput.value = selectedText;
    if (pane.ui.findReplaceInput) pane.ui.findReplaceInput.value = pane.findState.replace || '';
    pane.ui.findInput.focus();
    pane.ui.findInput.select();
    refreshPaneFind(pane, { resetIndex: true, focusEditor: false, preferSelection: true });
    updatePaneFindViewportIndicator(pane);
  }

  function showSimpleError(message) {
    if (typeof window.alert === 'function') window.alert(message);
  }

  const RESET_APP_CONFIRMATION_TEXT = 'RESET NOTO';
  const PROFILE_COLOR_STORAGE_KEY = 'notoProfileColors';
  const PASSWORD_PLACEHOLDER = '********';
  const PASSWORD_LENGTH_KEY = 'notoPasswordLength';
  const PASSWORD_PLAIN_KEY = 'notoPasswordPlain';
  let cachedPasswordPlain = '';
  let cachedPasswordLength = 0;

  function normalizeResetConfirmationInput(value) {
    return String(value || '')
      .trim()
      .replace(/\s+/g, ' ')
      .toUpperCase();
  }

  function clearLocalBrowserStateForReset() {
    try {
      window.localStorage.clear();
    } catch (error) {}
    try {
      window.sessionStorage.clear();
    } catch (error) {}
  }

  function loadPasswordFromLocalStorage() {
    let plain = '';
    let length = 0;
    try {
      plain = String(window.localStorage.getItem(PASSWORD_PLAIN_KEY) || '');
    } catch (e) {}
    try {
      const rawLen = Number(window.localStorage.getItem(PASSWORD_LENGTH_KEY));
      if (Number.isFinite(rawLen) && rawLen > 0) length = Math.floor(rawLen);
    } catch (e) {}
    if (plain) length = plain.length;
    cachedPasswordPlain = plain;
    cachedPasswordLength = length;
  }

  async function hydratePasswordCache() {
    if (window.authAPI && typeof window.authAPI.getPassword === 'function') {
      try {
        const result = await window.authAPI.getPassword();
        if (result && result.success) {
          const plain = typeof result.plain === 'string' ? result.plain : '';
          const lenRaw = Number(result.length);
          const length = Number.isFinite(lenRaw) && lenRaw >= 0 ? Math.floor(lenRaw) : (plain ? plain.length : 0);
          cachedPasswordPlain = plain;
          cachedPasswordLength = length;
          return;
        }
      } catch (e) {}
    }
    loadPasswordFromLocalStorage();
  }

  function readProfileColorMap() {
    try {
      const raw = window.localStorage.getItem(PROFILE_COLOR_STORAGE_KEY);
      const parsed = raw ? JSON.parse(raw) : {};
      return (parsed && typeof parsed === 'object') ? parsed : {};
    } catch (e) {
      return {};
    }
  }

  function writeProfileColorMap(map) {
    try {
      window.localStorage.setItem(PROFILE_COLOR_STORAGE_KEY, JSON.stringify(map || {}));
    } catch (e) {}
  }

  function getProfileHue(email) {
    const safeEmail = String(email || '').trim().toLowerCase();
    const map = readProfileColorMap();
    const existing = map && typeof map[safeEmail] === 'number' ? map[safeEmail] : null;
    if (Number.isFinite(existing)) return existing;
    const hue = Math.floor(Math.random() * 360);
    map[safeEmail] = hue;
    writeProfileColorMap(map);
    return hue;
  }

  function setProfileHue(email, hue) {
    const safeEmail = String(email || '').trim().toLowerCase();
    if (!safeEmail || !Number.isFinite(hue)) return;
    const map = readProfileColorMap();
    map[safeEmail] = hue;
    writeProfileColorMap(map);
  }

  function buildProfileColors(hue) {
    const activeTheme = String(document.documentElement.getAttribute('data-theme') || 'light');
    const accentSaturation = 74;
    const accentLightness = 76;
    const surfaceAlpha = activeTheme === 'dark' ? 0.46 : 0.34;
    const softAlpha = activeTheme === 'dark' ? 0.38 : 0.28;
    return {
      bg: `hsla(${hue}, ${accentSaturation}%, ${accentLightness}%, ${surfaceAlpha})`,
      fg: `hsl(${hue}, ${accentSaturation}%, ${accentLightness}%)`,
      soft: `hsla(${hue}, ${accentSaturation}%, ${accentLightness}%, ${softAlpha})`
    };
  }

  function getProfileColorOwnerEmail() {
    if (authSnapshot && authSnapshot.authenticated && authSnapshot.email) {
      return String(authSnapshot.email).trim().toLowerCase();
    }
    return 'guest';
  }

  function getCircularHueDistance(a, b) {
    const raw = Math.abs(a - b);
    return Math.min(raw, 360 - raw);
  }

  function highlightActiveProfileColor(email = getProfileColorOwnerEmail()) {
    if (!els.profileColorOptions || els.profileColorOptions.length === 0) return;
    const hue = getProfileHue(email || 'guest');
    let bestOption = null;
    let bestDistance = Number.POSITIVE_INFINITY;

    els.profileColorOptions.forEach((option) => {
      const optionHue = Number(option.dataset.hue);
      if (!Number.isFinite(optionHue)) return;
      const distance = getCircularHueDistance(optionHue, hue);
      if (distance < bestDistance) {
        bestDistance = distance;
        bestOption = option;
      }
    });

    els.profileColorOptions.forEach((option) => {
      const isActive = option === bestOption;
      option.classList.toggle('active', isActive);
      option.setAttribute('aria-pressed', isActive ? 'true' : 'false');
    });
  }

  function applyProfileColors(email) {
    const safeEmail = String(email || '').trim();
    const profileKey = safeEmail || getProfileColorOwnerEmail();
    const initial = safeEmail ? safeEmail[0].toUpperCase() : 'U';
    const hue = getProfileHue(profileKey);
    const activeTheme = String(document.documentElement.getAttribute('data-theme') || 'light');
    const guestColors = {
      bg: activeTheme === 'dark' ? '#ffffff' : '#000000',
      fg: activeTheme === 'dark' ? '#000000' : '#ffffff',
      soft: activeTheme === 'dark' ? '#ffffff' : '#000000'
    };
    const colors = profileKey === 'guest' ? guestColors : buildProfileColors(hue);
    const softAccent = colors.soft || `hsl(${hue}, 45%, 74%)`;

    if (els.profileInitial) els.profileInitial.textContent = initial;
    if (els.profileInitialCollapsed) els.profileInitialCollapsed.textContent = initial;
    if (els.profileAvatar) {
      els.profileAvatar.style.backgroundColor = colors.bg;
      els.profileAvatar.style.color = colors.fg;
    }
    if (els.profileAvatarCollapsed) {
      els.profileAvatarCollapsed.style.backgroundColor = colors.bg;
      els.profileAvatarCollapsed.style.color = colors.fg;
    }
    if (els.accountProfileAvatar) {
      els.accountProfileAvatar.style.backgroundColor = colors.bg;
      els.accountProfileAvatar.style.color = colors.fg;
    }
    if (els.accountProfileInitial) {
      els.accountProfileInitial.textContent = initial;
    }
    document.documentElement.style.setProperty('--profile-accent', colors.fg);
    document.documentElement.style.setProperty('--profile-accent-soft', softAccent);
    highlightActiveProfileColor(profileKey);
  }

  function readPasswordLength() {
    return cachedPasswordLength;
  }

  function readPasswordPlain() {
    return cachedPasswordPlain;
  }

  function buildPasswordDots(length) {
    const safeLength = Math.max(0, Math.min(64, Number(length) || 0));
    if (safeLength === 0) return PASSWORD_PLACEHOLDER;
    return '?'.repeat(safeLength);
  }

  function setPasswordMasked() {
    if (!els.profilePassword) return;
    const plain = readPasswordPlain();
    const length = plain ? plain.length : readPasswordLength();
    const dots = buildPasswordDots(length);
    els.profilePassword.type = 'password';
    els.profilePassword.value = dots;
  }

  function updateProfileAuthControls(isAuthenticated) {
    if (els.logoutBtn) {
      els.logoutBtn.disabled = false;
      els.logoutBtn.innerHTML = isAuthenticated ? ICONS.LOG_OUT : ICONS.LOG_IN;
      els.logoutBtn.setAttribute('aria-label', isAuthenticated ? 'Log out' : 'Sign in');
      els.logoutBtn.setAttribute('data-custom-title', isAuthenticated ? 'Log out' : 'Sign in');
      els.logoutBtn.classList.toggle('is-login', !isAuthenticated);
    }
    if (els.deleteAccountBtn) {
      els.deleteAccountBtn.hidden = !isAuthenticated;
      els.deleteAccountBtn.disabled = !isAuthenticated;
    }
    if (els.profilePasswordToggle) {
      els.profilePasswordToggle.disabled = !isAuthenticated;
      if (!isAuthenticated) els.profilePasswordToggle.classList.remove('is-revealed');
    }
    if (els.profilePassword) {
      els.profilePassword.disabled = !isAuthenticated;
    }
  }

  async function performSignOut() {
    let state = null;
    try {
      if (window.authAPI && typeof window.authAPI.getState === 'function') {
        state = await window.authAPI.getState();
      }
    } catch (e) {}

    const isAuthed = Boolean(state && state.authenticated);
    if (!isAuthed) {
      window.location.replace('login.html');
      return { success: true };
    }

    try {
      if (window.authAPI && typeof window.authAPI.signOut === 'function') {
        await window.authAPI.signOut();
      }
      closeModal();
      await refreshProfileIdentity();
      await refreshCollabInviteIndicator();
      scheduleCloudPolling();
      showToast('Signed out.', 'info');
      return { success: true };
    } catch (e) {
      showToast('Failed to sign out.', 'warning');
      return { success: false };
    }
  }

  async function refreshProfileIdentity() {
    let email = '';
    let authenticated = false;

    if (window.authAPI && typeof window.authAPI.getState === 'function') {
      try {
        const state = await window.authAPI.getState();
        if (state && typeof state.email === 'string') email = state.email;
        authenticated = Boolean(state && state.authenticated);
      } catch (e) {}
    }

    authSnapshot = { authenticated, email };
    const displayEmail = authenticated && email ? email : 'Not signed in';
    currentUserEmail = authenticated && email ? email : '';
    refreshLiveCloudIndicators();
    panes.forEach((pane) => updatePaneUploadMenuAction(pane));
    applyProfileColors(authenticated && email ? email : 'guest');
    if (els.profileEmail) els.profileEmail.textContent = displayEmail;
    if (els.profileEmailDisplay) els.profileEmailDisplay.textContent = displayEmail;

    if (authenticated) {
      await hydratePasswordCache();
    } else {
      cachedPasswordPlain = '';
      cachedPasswordLength = 0;
    }
    setPasswordMasked();
    updateProfileAuthControls(authenticated);

    if (!authenticated) {
      setCollabInviteIndicator(0);
      writeCollabInviteCache([]);
      renderSubscriptionStatus();
      return;
    }
    renderSubscriptionStatus();
  }

  function clearModalCleanup() {
    if (!modalCleanup) return;
    const cleanup = modalCleanup;
    modalCleanup = null;
    cleanup();
  }

  function bindModalCloseHandlers() {
    if (!els.modalBackdrop) return;
    clearModalCleanup();
    const onKeyDown = (e) => {
      if (e.key === 'Escape') {
        e.preventDefault();
        closeModal();
      }
    };
    const onBackdropClick = (e) => {
      if (e.target === els.modalBackdrop) closeModal();
    };
    document.addEventListener('keydown', onKeyDown);
    els.modalBackdrop.addEventListener('mousedown', onBackdropClick);
    modalCleanup = () => {
      document.removeEventListener('keydown', onKeyDown);
      els.modalBackdrop.removeEventListener('mousedown', onBackdropClick);
    };
  }

  function closeModal() {
    if (!els.modalBackdrop || !els.modalEl) return;
    clearModalCleanup();
    els.modalBackdrop.setAttribute('aria-hidden', 'true');
    els.modalBackdrop.style.display = '';
    // Close any portaled dropdown panels that may have been moved to document.body
    try {
      const portaled = Array.from(document.querySelectorAll('.is-portal'));
      portaled.forEach((panel) => {
        try {
          if (typeof unportalPanelFromBody === 'function') {
            try { unportalPanelFromBody(panel); } catch (e) {}
            return;
          }
          if (panel._portalRepositionHandler) {
            window.removeEventListener('resize', panel._portalRepositionHandler);
            window.removeEventListener('scroll', panel._portalRepositionHandler, { passive: true });
            delete panel._portalRepositionHandler;
          }
          panel.classList.remove('is-portal');
          if (panel._portalOriginalParent) {
            const parent = panel._portalOriginalParent;
            try {
              if (panel._portalOriginalNextSibling && parent.contains(panel._portalOriginalNextSibling)) {
                parent.insertBefore(panel, panel._portalOriginalNextSibling);
              } else {
                parent.appendChild(panel);
              }
            } catch (err) {
              if (parent && parent.appendChild) parent.appendChild(panel);
            }
            delete panel._portalOriginalParent;
            delete panel._portalOriginalNextSibling;
          } else {
            if (panel.parentNode) panel.parentNode.removeChild(panel);
          }
          panel.style.position = '';
          panel.style.left = '';
          panel.style.top = '';
          panel.style.width = '';
          panel.style.right = '';
          panel.style.minWidth = '';
          panel.style.maxWidth = '';
          panel.style.zIndex = '';
          panel.hidden = true;
        } catch (err) {
          // swallow
        }
      });
    } catch (err) {
      // swallow
    }
    els.modalEl.classList.remove('settings-shell-modal');
    els.modalEl.classList.remove('create-item-modal');
    els.modalEl.removeAttribute('aria-label');
    els.modalEl.innerHTML = '';
  }

  function normalizeQuickCreateNoteName(rawName) {
    return String(rawName || '')
      .replace(/^\/+/, '')
      .replace(/[\\/:*?"<>|]+/g, ' ')
      .replace(/\s+/g, ' ')
      .replace(/\.md$/i, '')
      .trim();
  }

  function stopHandledKeyboardEvent(event) {
    if (!event) return;
    event.preventDefault();
    event.stopPropagation();
    if (typeof event.stopImmediatePropagation === 'function') {
      event.stopImmediatePropagation();
    }
  }

  function shouldRetainTabInLiveEditor(pane, event) {
    if (!pane || !pane.ui || !pane.ui.liveEditor || !pane.live || !pane.live.cmApi || !pane.live.cmView) {
      return false;
    }
    const editor = pane.ui.liveEditor;
    const targetEl = event && event.target instanceof Element ? event.target : null;
    const activeEl = document.activeElement instanceof Element ? document.activeElement : null;
    if (targetEl && targetEl.closest && targetEl.closest('.noto-table-cell-input, .cm-search, .cm-panel')) {
      return false;
    }
    if (activeEl && activeEl.closest && activeEl.closest('.noto-table-cell-input, .cm-search, .cm-panel')) {
      return false;
    }
    if (targetEl && editor.contains(targetEl)) return true;
    if (activeEl && editor.contains(activeEl)) return true;
    return Boolean(pane.live.cmView && pane.live.cmView.hasFocus);
  }

  function handleLiveEditorTabRetention(pane, event) {
    if (!event || event.key !== 'Tab') return false;
    if (!shouldRetainTabInLiveEditor(pane, event)) return false;
    const cmApi = pane && pane.live ? pane.live.cmApi : null;
    if (!cmApi || typeof cmApi.handleTab !== 'function') return false;
    const handled = cmApi.handleTab(event.shiftKey);
    if (!handled) return false;
    stopHandledKeyboardEvent(event);
    return true;
  }

  async function ensureQuickCreateFolderPath(folderPath = '') {
    const safeFolderPath = normalizeStoragePath(folderPath);
    if (!safeFolderPath) return { success: true, path: '' };
    if (safeFolderPath.split('/').some((segment) => segment === '.' || segment === '..')) {
      return { success: false, error: 'Folder path is invalid.' };
    }
    const result = await window.api.createFolder(safeFolderPath);
    if (result && result.success) {
      return {
        success: true,
        path: normalizeStoragePath(result.path || safeFolderPath) || safeFolderPath
      };
    }
    if (result && /already exists/i.test(String(result.error || ''))) {
      return { success: true, path: safeFolderPath };
    }
    return {
      success: false,
      error: (result && result.error) ? result.error : 'Failed to prepare target folder.'
    };
  }

  async function buildQuickCreateNoteTarget(noteName, folderPath = '') {
    const safeBaseName = normalizeQuickCreateNoteName(noteName);
    if (!safeBaseName) {
      return { success: false, error: 'Note name is required.' };
    }

    const ensuredFolder = await ensureQuickCreateFolderPath(folderPath);
    if (!ensuredFolder.success) return ensuredFolder;

    const targetFolderPath = normalizeStoragePath(ensuredFolder.path || '');
    const existingItemsRaw = await window.electronAPI.getFiles(targetFolderPath);
    const existingItems = Array.isArray(existingItemsRaw) ? existingItemsRaw : [];
    const existingNames = new Set(
      existingItems
        .filter((item) => item && !item.isDirectory)
        .map((item) => String(item.name || '').trim().toLowerCase())
        .filter(Boolean)
    );

    let finalName = `${safeBaseName}.md`;
    let counter = 1;
    while (existingNames.has(finalName.toLowerCase())) {
      finalName = `${safeBaseName}-${counter}.md`;
      counter += 1;
    }

    return {
      success: true,
      finalName,
      folderPath: targetFolderPath,
      relativePath: targetFolderPath ? `${targetFolderPath}/${finalName}` : finalName
    };
  }

  async function createQuickSearchNote(noteName, folderPath = '') {
    const target = await buildQuickCreateNoteTarget(noteName, folderPath);
    if (!target || !target.success) {
      return {
        success: false,
        error: (target && target.error) ? target.error : 'Failed to prepare note path.'
      };
    }

    const result = await window.api.createFile(target.relativePath, '');
    if (!result || !result.success) {
      return {
        success: false,
        error: (result && result.error) ? result.error : 'Failed to create note.'
      };
    }

    const createdPath = normalizeStoragePath(
      (typeof result.path === 'string' && result.path) ? result.path : target.relativePath
    ) || normalizeStoragePath(target.relativePath);

    if (!activePane) createPane();
    await openPathAsIndividualTab(createdPath, target.finalName, '');
    await revealPathInSidebar(createdPath);
    saveAppState();
    queueSearchIndexRefresh({ delayMs: 0 });
    showToast(
      `Created note "${target.finalName.replace(/\.md$/i, '')}" in "${target.folderPath || 'root'}".`,
      'success'
    );

    return {
      success: true,
      path: createdPath,
      name: target.finalName,
      folderPath: target.folderPath || ''
    };
  }

  function showQuickCreateFolderPrompt(noteName) {
    if (
      !quickFolderPickerUI.popup
      || !quickFolderPickerUI.input
      || !quickFolderPickerUI.actionBtn
      || !quickFolderPickerUI.list
    ) {
      return Promise.resolve({ cancelled: true });
    }
    const safeNoteName = normalizeQuickCreateNoteName(noteName);
    if (!safeNoteName) return Promise.resolve({ cancelled: true });

    return new Promise((resolve) => {
      let finished = false;
      let folderEntries = [];
      let folderEntriesReady = false;
      let folderLoadFailed = false;
      let renderedChoices = [];
      let selectionIndex = -1;
      const popup = quickFolderPickerUI.popup;
      const input = quickFolderPickerUI.input;
      const actionBtn = quickFolderPickerUI.actionBtn;
      const list = quickFolderPickerUI.list;
      const defaultHint = 'Press Enter to skip to root, or type to search for a folder.';
      if (quickFolderPickerUI.title) {
        quickFolderPickerUI.title.textContent = `Add "${safeNoteName}" to a specific folder`;
      }
      if (quickFolderPickerUI.hint) {
        quickFolderPickerUI.hint.textContent = defaultHint;
      }

      const getResultItems = () => Array.from(list.querySelectorAll('li[data-folder-picker-result="1"]'));
      const setSelection = (index, options = {}) => {
        const items = getResultItems();
        if (!items.length) {
          selectionIndex = -1;
          return;
        }
        const normalized = ((Number(index) % items.length) + items.length) % items.length;
        selectionIndex = normalized;
        items.forEach((item, itemIndex) => {
          item.classList.toggle('selected', itemIndex === normalized);
        });
        if (options.scrollIntoView !== false) {
          const target = items[normalized];
          if (target && typeof target.scrollIntoView === 'function') {
            target.scrollIntoView({ block: 'nearest' });
          }
        }
      };
      const stepSelection = (delta) => {
        const items = getResultItems();
        if (!items.length) {
          selectionIndex = -1;
          return;
        }
        if (selectionIndex < 0) {
          setSelection(delta >= 0 ? 0 : (items.length - 1));
          return;
        }
        setSelection(selectionIndex + delta);
      };
      const updateActionButton = () => {
        const hasValue = Boolean(String(input.value || '').trim());
        actionBtn.textContent = hasValue ? 'Save' : 'Skip';
        actionBtn.classList.toggle('is-commit', hasValue);
      };
      const buildChoices = (query) => {
        const rawQuery = String(query || '').trim();
        const normalizedQuery = normalizeStoragePath(rawQuery);
        const terms = getQuickCreateFolderTerms(rawQuery);
        const matches = folderEntries
          .map((entry) => scoreQuickCreateFolderEntry(entry, rawQuery, terms))
          .filter(Boolean)
          .sort((left, right) => (
            right.score - left.score
            || left.entry.path.length - right.entry.path.length
            || left.entry.path.localeCompare(right.entry.path)
          ))
          .slice(0, 40)
          .map((hit) => ({
            kind: 'existing',
            path: hit.entry.path,
            name: hit.entry.name,
            label: hit.entry.name,
            pathLabel: hit.entry.path,
            snippet: ''
          }));
        if (normalizedQuery) {
          const exactExisting = folderEntries.some((entry) => entry.pathLower === normalizedQuery.toLowerCase());
          if (!exactExisting) {
            matches.push({
              kind: 'typed',
              path: normalizedQuery,
              name: normalizedQuery.split('/').pop() || normalizedQuery,
              label: `Create or use "${normalizedQuery}"`,
              pathLabel: normalizedQuery,
              snippet: 'This folder path will be created automatically if it does not exist.'
            });
          }
        }
        return matches;
      };
      const renderChoices = () => {
        const rawQuery = String(input.value || '').trim();
        updateActionButton();
        renderedChoices = [];
        selectionIndex = -1;
        list.classList.remove('is-loading');
        list.innerHTML = '';

        if (!rawQuery) {
          list.hidden = true;
          return;
        }

        list.hidden = false;
        if (!folderEntriesReady && !folderLoadFailed) {
          list.classList.add('is-loading');
          const loadingItem = document.createElement('li');
          loadingItem.style.color = 'var(--muted-strong, var(--text-sub))';
          loadingItem.textContent = 'Loading folders...';
          list.appendChild(loadingItem);
          return;
        }

        if (folderLoadFailed) {
          const failedItem = document.createElement('li');
          failedItem.style.color = 'var(--danger-fg, #c9342f)';
          failedItem.textContent = 'Unable to load folders right now.';
          list.appendChild(failedItem);
          return;
        }

        renderedChoices = buildChoices(rawQuery);
        if (!renderedChoices.length) {
          const emptyItem = document.createElement('li');
          emptyItem.style.color = 'var(--muted-strong, var(--text-sub))';
          emptyItem.textContent = 'No matching folders.';
          list.appendChild(emptyItem);
          return;
        }

        const terms = getQuickCreateFolderTerms(rawQuery);
        renderedChoices.forEach((choice, choiceIndex) => {
          const li = document.createElement('li');
          li.setAttribute('data-folder-picker-result', '1');
          li.setAttribute('tabindex', '-1');
          const nameHtml = highlightSearchTerms(choice.label || choice.name || choice.path, terms);
          const pathHtml = choice.pathLabel ? highlightSearchTerms(choice.pathLabel, terms) : '';
          const snippetHtml = choice.snippet ? highlightSearchTerms(choice.snippet, terms) : '';
          li.innerHTML = `
            <div class="search-result-main">
              ${ICONS.FOLDER}
              <span class="search-result-name">${nameHtml}</span>
              ${pathHtml ? `<span class="path-sub">${pathHtml}</span>` : ''}
            </div>
            ${snippetHtml ? `<div class="search-result-snippet">${snippetHtml}</div>` : ''}
          `;
          li.addEventListener('mouseenter', () => {
            setSelection(choiceIndex, { scrollIntoView: false });
          });
          li.addEventListener('click', () => {
            finish({ cancelled: false, folderPath: choice.path || '' });
          });
          list.appendChild(li);
        });

        if (getResultItems().length) {
          setSelection(0, { scrollIntoView: false });
        }
      };
      const submitChoice = () => {
        const rawValue = String(input.value || '').trim();
        if (!rawValue) {
          finish({ cancelled: false, folderPath: '' });
          return;
        }
        if (!folderEntriesReady && !folderLoadFailed) {
          if (quickFolderPickerUI.hint) {
            quickFolderPickerUI.hint.textContent = 'Loading folders... press Enter again in a moment, or wait for the matches below.';
          }
          return;
        }
        const selectedChoice = renderedChoices[selectionIndex >= 0 ? selectionIndex : 0] || null;
        if (selectedChoice && selectedChoice.path) {
          finish({ cancelled: false, folderPath: selectedChoice.path });
          return;
        }
        const safeFolder = normalizeStoragePath(rawValue);
        if (!safeFolder) {
          if (quickFolderPickerUI.hint) {
            quickFolderPickerUI.hint.textContent = 'Type a folder name, or press Enter to skip to root.';
          }
          return;
        }
        finish({ cancelled: false, folderPath: safeFolder });
      };
      const cleanup = () => {
        document.removeEventListener('keydown', onDocumentKeyDown, true);
        document.removeEventListener('mousedown', onDocumentPointerDown, true);
        window.removeEventListener('resize', onResize);
        input.removeEventListener('input', onInput);
        input.removeEventListener('keydown', onInputKeyDown);
        actionBtn.removeEventListener('click', onActionClick);
        activeQuickCreateFolderPromptCloser = null;
      };
      const finish = (payload = { cancelled: true }) => {
        if (finished) return;
        finished = true;
        cleanup();
        setCenteredPopupOpen(popup, false);
        input.value = '';
        updateActionButton();
        list.hidden = true;
        list.classList.remove('is-loading');
        list.innerHTML = '';
        resolve(payload);
      };
      const onDocumentKeyDown = (event) => {
        if (!popup.classList.contains('is-open')) return;
        if (event.key === 'Escape') {
          event.preventDefault();
          finish({ cancelled: true });
        }
      };
      const onDocumentPointerDown = (event) => {
        if (!popup.classList.contains('is-open')) return;
        if (popup.contains(event.target)) return;
        finish({ cancelled: true });
      };
      const onResize = () => {
        if (!popup.classList.contains('is-open')) return;
        setCenteredPopupWidth(popup, {
          maxWidth: SEARCH_OPEN_MAX_WIDTH_PX,
          minWidth: 420,
          widthRatio: 0.56
        });
      };
      const onInput = () => {
        if (quickFolderPickerUI.hint) {
          quickFolderPickerUI.hint.textContent = defaultHint;
        }
        renderChoices();
      };
      const onInputKeyDown = (event) => {
        if (event.key === 'ArrowDown' && !list.hidden) {
          event.preventDefault();
          stepSelection(1);
          return;
        }
        if (event.key === 'ArrowUp' && !list.hidden) {
          event.preventDefault();
          stepSelection(-1);
          return;
        }
        if (event.key === 'Tab' && !list.hidden) {
          event.preventDefault();
          stepSelection(event.shiftKey ? -1 : 1);
          return;
        }
        if (event.key === 'Enter') {
          event.preventDefault();
          submitChoice();
        }
      };
      const onActionClick = (event) => {
        event.preventDefault();
        submitChoice();
      };

      activeQuickCreateFolderPromptCloser = () => finish({ cancelled: true });
      input.value = '';
      updateActionButton();
      list.hidden = true;
      list.innerHTML = '';
      list.classList.remove('is-loading');
      setCenteredPopupWidth(popup, {
        maxWidth: SEARCH_OPEN_MAX_WIDTH_PX,
        minWidth: 420,
        widthRatio: 0.56
      });
      setCenteredPopupOpen(popup, true);
      document.addEventListener('keydown', onDocumentKeyDown, true);
      document.addEventListener('mousedown', onDocumentPointerDown, true);
      window.addEventListener('resize', onResize);
      input.addEventListener('input', onInput);
      input.addEventListener('keydown', onInputKeyDown);
      actionBtn.addEventListener('click', onActionClick);
      input.focus();

      getQuickCreateFolderEntries()
        .then((entries) => {
          if (finished) return;
          folderEntries = Array.isArray(entries) ? entries : [];
          folderEntriesReady = true;
          renderChoices();
        })
        .catch(() => {
          if (finished) return;
          folderEntriesReady = true;
          folderLoadFailed = true;
          renderChoices();
        });
    });
  }

  async function handleQuickCreateNoteFromSearch(noteName) {
    const safeNoteName = normalizeQuickCreateNoteName(noteName);
    if (!safeNoteName) {
      showToast('Type a note name after "/".', 'info');
      return;
    }
    const choice = await showQuickCreateFolderPrompt(safeNoteName);
    if (!choice || choice.cancelled) return;
    const result = await createQuickSearchNote(safeNoteName, choice.folderPath || '');
    if (!result || !result.success) {
      showToast(
        (result && result.error) ? result.error : 'Failed to create note.',
        'warning'
      );
    }
  }

