  function showManagePresentationModal(sourcePane = null, sourceTab = null) {
    if (!livePresentation.isOpen) {
      if (sourcePane && sourceTab) {
        showDisplayPicker(sourcePane, sourceTab);
      }
      return;
    }
    if (!els.modalBackdrop || !els.modalEl) return;

    const sourceContext = getLivePresentationSourceContext();
    const sourceLabel = sourceContext && sourceContext.tab && sourceContext.tab.path
      ? getNoteDisplayName(sourceContext.tab.path.split('/').pop())
      : 'Unknown note';
    els.modalEl.innerHTML = '';

    const header = buildModalHeader(
      'Manage presentation',
      `Source note: ${sourceLabel}`
    );

    const statusSection = document.createElement('div');
    statusSection.className = 'modal-section';
    const statusRow = document.createElement('div');
    statusRow.className = 'modal-display-status';
    const statusTitle = document.createElement('strong');
    statusTitle.textContent = 'Status';
    const statusValue = document.createElement('span');
    statusValue.className = 'modal-display-status-value';
    statusRow.append(statusTitle, statusValue);
    statusSection.append(statusRow);

    const actions = document.createElement('div');
    actions.className = 'actions';

    const doneBtn = document.createElement('button');
    doneBtn.id = 'modal-cancel';
    doneBtn.textContent = 'Done';

    const freezeBtn = document.createElement('button');
    freezeBtn.className = 'btn-secondary';
    freezeBtn.type = 'button';

    const endBtn = document.createElement('button');
    endBtn.className = 'btn-danger';
    endBtn.type = 'button';

    const setIconButtonContent = (button, iconSvg, text) => {
      button.innerHTML = `<span class="btn-label-icon" aria-hidden="true">${iconSvg}</span><span>${text}</span>`;
    };

    const refreshState = () => {
      const frozen = Boolean(livePresentation.isFrozen);
      statusValue.textContent = frozen ? 'Frozen' : 'Live';
      setIconButtonContent(
        freezeBtn,
        frozen ? ICONS.PRESENTATION_UNFREEZE : ICONS.PRESENTATION_FREEZE,
        frozen ? 'Unfreeze' : 'Freeze'
      );
      setIconButtonContent(endBtn, ICONS.PRESENTATION_END, 'End');
    };

    refreshState();

    freezeBtn.onclick = () => {
      const nextFrozen = !livePresentation.isFrozen;
      if (!setLivePresentationFrozen(nextFrozen)) return;
      refreshState();
      showToast(nextFrozen ? 'Presentation frozen.' : 'Presentation resumed.', 'info', 1600);
    };

    endBtn.onclick = async () => {
      freezeBtn.disabled = true;
      endBtn.disabled = true;
      doneBtn.disabled = true;
      await endLivePresentation();
      closeModal();
      showToast('Presentation ended.', 'info', 1600);
    };

    doneBtn.onclick = () => closeModal();

    actions.append(doneBtn, freezeBtn, endBtn);

    const footerSection = document.createElement('div');
    footerSection.className = 'modal-section';
    footerSection.append(actions);

    els.modalEl.append(header, statusSection, footerSection);
    els.modalBackdrop.setAttribute('aria-hidden', 'false');
    bindModalCloseHandlers();
  }

